import React, { useState } from 'react';
import { useGame } from '../../../context/GameContext';
import DialogueBox from '../../DialogueBox';
import { Store, Heart } from 'lucide-react';
import { getAssetUrl } from '../../../utils';
import { useShop } from './hooks/useShop';

// Sub-components
import { ShopSign } from './ui/ShopSign';
import { AnimatedMercenary } from '../../common/ui/AnimatedMercenary';
import { CustomerHUD } from './ui/CustomerHUD';
import { ShopQueueBadge } from './ui/ShopQueueBadge';
import { ShopClosedOverlay } from './ui/ShopClosedOverlay';
import { InstanceSelectorPopup } from './ui/InstanceSelectorPopup';

interface ShopTabProps {
    onNavigate: (tab: any) => void;
}

const ShopTab: React.FC<ShopTabProps> = ({ onNavigate }) => {
  const { state, actions } = useGame();
  const shop = useShop();
  const [counterImgError, setCounterImgError] = useState(false);

  // 튜토리얼 중 상점 열기 단계인지 확인
  const isOpeningStep = state.tutorialStep === 'OPEN_SHOP_SIGN_GUIDE';

  return (
    <div className="relative h-full w-full bg-stone-900 overflow-hidden flex flex-col items-center justify-center">
        {/* Background Layer */}
        <div className="absolute inset-0 z-0">
            <img 
                src={getAssetUrl('shop_bg.jpeg', 'bg')} 
                className="absolute top-0 opacity-60 w-full h-full object-cover"
                onError={(e) => { e.currentTarget.style.display = 'none'; e.currentTarget.parentElement!.style.background = 'linear-gradient(to bottom, #292524, #1c1917)'; }}
            />
        </div>

        {/* Floating Sign */}
        <ShopSign 
            isOpen={shop.isShopOpen} 
            onToggle={shop.handlers.handleToggleShop} 
            disabled={isOpeningStep ? false : ((!shop.isShopOpen && !shop.canAffordOpen) || shop.isTutorialActive)}
        />

        {/* UI Elements: Queue & HUD */}
        {shop.isShopOpen && shop.dialogueState && (
            <>
                <ShopQueueBadge count={shop.shopQueue.length} />
                {shop.activeCustomer && (
                    <CustomerHUD 
                        mercenary={shop.activeCustomer.mercenary} 
                        refusalReaction={shop.refusalReaction} 
                    />
                )}
            </>
        )}

        {/* Character Stage - Anchored to bottom of ShopTab */}
        <div className="absolute inset-0 z-10 w-full h-full flex flex-col items-center justify-end pointer-events-none">
        {shop.isShopOpen && shop.activeCustomer && shop.dialogueState && (
            <div className="relative flex justify-center items-end w-full h-full animate-in fade-in zoom-in-95 duration-700 ease-out">
                {/* ✅ ShopTab(=h-full) 기준 80% 스테이지 */}
                <div className="relative w-full h-[80%] flex items-end justify-center">
                    {shop.floatingHearts.map((heart) => (
                    <Heart
                        key={heart.id}
                        className="absolute animate-heart fill-pink-500 text-pink-400 drop-shadow-[0_0_12px_rgba(236,72,153,0.8)] z-0"
                        style={{
                        left: `${heart.left}%`,
                        bottom: '40%',
                        width: heart.size,
                        height: heart.size,
                        animationDelay: `${heart.delay}s`,
                        '--wobble': `${(Math.random() - 0.5) * 60}px`,
                        } as React.CSSProperties}
                    />
                    ))}

                    {/* ✅ height prop 제거 + h-full로 스테이지에 정확히 맞춤 */}
                    <AnimatedMercenary
                        mercenary={shop.activeCustomer.mercenary}
                        className={`h-full w-auto object-contain object-bottom filter drop-shadow-[0_0_100px_rgba(0,0,0,0.95)] transition-all duration-500 relative z-10 ${
                            shop.refusalReaction === 'ANGRY' ? 'brightness-50 sepia-50' : ''
                        }`}
                    />

                    <div className="absolute bottom-10 left-1/2 -translate-x-1/2 w-80 h-16 bg-black/60 blur-3xl rounded-full -z-10"></div>
                </div>
            </div>
        )}
        </div>

        {/* Shop Counter */}
        <div className="absolute bottom-0 w-full h-[35dvh] md:h-64 z-20 flex items-end justify-center pointer-events-none">
            {!counterImgError ? (
                <img 
                    src={getAssetUrl('shop_counter.png', 'bg')} 
                    className="w-full h-full object-cover object-top filter drop-shadow-[0_-30px_50px_rgba(0,0,0,0.8)]"
                    onError={() => setCounterImgError(true)}
                />
            ) : (
                <div className="w-full h-full bg-[#3f2e22] border-t-2 md:border-t-[8px] border-[#5d4037] shadow-[0_-40px_60px_rgba(0,0,0,0.85)] relative overflow-hidden">
                    <div className="absolute inset-0 opacity-20" style={{ backgroundImage: 'repeating-linear-gradient(45deg, transparent, transparent 10px, #000 10px, #000 12px)' }}></div>
                </div>
            )}
        </div>

        {/* Dialogue Box */}
        <div className="absolute bottom-6 md:bottom-12 left-1/2 -translate-x-1/2 w-[92vw] md:w-[85vw] max-w-5xl z-50 flex flex-col items-center pointer-events-auto">
            {shop.isShopOpen && shop.dialogueState && (
                 <DialogueBox 
                    speaker={shop.dialogueState.speaker}
                    text={shop.dialogueState.text}
                    options={shop.dialogueState.options}
                    // Fix: Use type assertion to access optional properties in union type
                    highlightTerm={(shop.dialogueState as any).highlightTerm}
                    // Fix: Use type assertion to access optional properties in union type
                    itemDetail={(shop.dialogueState as any).itemDetail}
                    className="w-full relative pointer-events-auto"
                />
            )}
        </div>

        {/* Modals & Overlays */}
        <InstanceSelectorPopup 
            show={shop.showInstanceSelector}
            onClose={() => shop.handlers.setShowInstanceSelector(false)}
            matchingItems={shop.matchingItems}
            selectedInstance={shop.selectedInstance}
            onSelect={shop.handlers.setSelectedInstance}
            onSell={shop.handlers.executeSell}
            onToggleLock={(id) => actions.toggleLockItem(id)}
            customerMarkup={shop.activeCustomer?.request.markup || 1.25}
        />

        <ShopClosedOverlay 
            isOpen={shop.isShopOpen}
            canAffordOpen={shop.canAffordOpen}
            onNavigate={onNavigate}
        />

        {shop.isShopOpen && !shop.activeCustomer && (
            <div className="absolute inset-0 z-20 flex flex-col items-center justify-center pointer-events-none pb-20">
                <div className="text-center animate-in fade-in zoom-in duration-1000">
                    <div className="w-20 h-20 md:w-28 md:h-28 bg-black/40 rounded-full flex items-center justify-center mx-auto mb-4 border border-white/10 backdrop-blur-xl shadow-inner">
                        <Store className="w-10 h-10 md:w-12 md:h-12 text-stone-700 animate-pulse" />
                    </div>
                    <h3 className="text-lg md:text-2xl font-black text-stone-500 uppercase tracking-[0.3em] opacity-40">Awaiting Customers</h3>
                </div>
            </div>
        )}
    </div>
  );
};

export default ShopTab;

import { useState, useEffect, useCallback, useMemo } from 'react';
import { useGame } from '../../../../context/GameContext';
import { EQUIPMENT_ITEMS } from '../../../../data/equipment';
import { materials } from '../../../../data/materials';
import { GAME_CONFIG } from '../../../../config/game-config';
import { InventoryItem } from '../../../../types/inventory';
import { getAssetUrl as globalGetAssetUrl } from '../../../../utils';

interface FloatingHeart {
    id: number;
    left: number;
    delay: number;
    size: number;
}

export const useShop = () => {
    const { state, actions } = useGame();
    const { isShopOpen } = state.forge;
    const { activeCustomer, shopQueue, tutorialStep, inventory } = state;

    const [floatingHearts, setFloatingHearts] = useState<FloatingHeart[]>([]);
    const [saleCompleted, setSaleCompleted] = useState(false);
    const [lastSoldQuality, setLastSoldQuality] = useState<number>(100);
    const [refusalReaction, setRefusalReaction] = useState<'POLITE' | 'ANGRY' | null>(null);
    const [showInstanceSelector, setShowInstanceSelector] = useState(false);
    const [selectedInstance, setSelectedInstance] = useState<InventoryItem | null>(null);

    useEffect(() => {
        if (!activeCustomer) {
            setSaleCompleted(false);
            setRefusalReaction(null);
            setShowInstanceSelector(false);
            setSelectedInstance(null);
        }
    }, [activeCustomer]);

    const spawnHearts = useCallback((count: number) => {
        const newHearts = Array.from({ length: count }).map((_, i) => ({
            id: Date.now() + i,
            left: 40 + Math.random() * 20,
            delay: Math.random() * 0.5,
            size: 16 + Math.random() * 12
        }));
        setFloatingHearts(prev => [...prev, ...newHearts]);
        setTimeout(() => setFloatingHearts([]), 3500);
    }, []);

    const getItemName = useCallback((id: string) => {
        const eq = EQUIPMENT_ITEMS.find(e => e.id === id);
        if (eq) return eq.name;
        const res = Object.values(materials).find(i => i.id === id);
        return res ? res.name : id;
    }, []);

    const matchingItems = useMemo(() => {
        if (!activeCustomer) return [];
        const { request } = activeCustomer;
        if (request.type === 'RESOURCE') {
            return inventory.filter(i => i.id === request.requestedId);
        } else {
            return inventory.filter(i => i.id.startsWith(request.requestedId));
        }
    }, [activeCustomer, inventory]);

    const executeSell = useCallback((item: InventoryItem) => {
        if (!activeCustomer || !item) return;
        if (item.isLocked) {
            actions.showToast("Item is locked and cannot be sold.");
            return;
        }
        const { mercenary, request } = activeCustomer;
        const isPipTutorial = tutorialStep === 'SELL_ITEM_GUIDE' && mercenary.id === 'pip_green';

        const itemQuality = item.equipmentData?.quality || 100;
        setLastSoldQuality(itemQuality);

        let affinityGain = isPipTutorial ? 10 : 2;
        if (itemQuality > 100) affinityGain += 2;
        else if (itemQuality < 80) affinityGain = Math.max(1, affinityGain - 1);

        const markup = request.markup || 1.25;
        const finalPrice = Math.ceil(item.baseValue * markup);

        if (item.type === 'RESOURCE') {
            actions.sellItem(item.id, 1, finalPrice, undefined, mercenary);
        } else {
            actions.sellItem(item.id, 1, finalPrice, item.id, mercenary);
        }

        spawnHearts(affinityGain);
        setSaleCompleted(true);
        setShowInstanceSelector(false);
        setSelectedInstance(null);
    }, [activeCustomer, tutorialStep, actions, spawnHearts]);

    const handleSellClick = useCallback(() => {
        if (!activeCustomer) return;
        if (matchingItems.length > 1) {
            setShowInstanceSelector(true);
        } else if (matchingItems.length === 1) {
            executeSell(matchingItems[0]);
        }
    }, [activeCustomer, matchingItems, executeSell]);

    const handleRefuse = useCallback(() => {
        if (!activeCustomer) return;
        const { mercenary } = activeCustomer;
        const affinity = mercenary.affinity || 0;
        const politeChance = affinity > 40 ? 0.8 : 0.3;
        const isPolite = Math.random() < politeChance;
        if (isPolite) {
            setRefusalReaction('POLITE');
            actions.refuseCustomer(mercenary.id, 0);
        } else {
            setRefusalReaction('ANGRY');
            actions.refuseCustomer(mercenary.id, 5);
        }
    }, [activeCustomer, actions]);

    const handleFarewell = useCallback(() => {
        setSaleCompleted(false);
        setRefusalReaction(null);
        actions.dismissCustomer();
    }, [actions]);

    const handleToggleShop = useCallback(() => {
        const isOpeningStep = state.tutorialStep === 'OPEN_SHOP_SIGN_GUIDE';

        // 튜토리얼 중이고 아직 상점이 닫힌 상태라면 무조건 열 수 있도록 유도
        if (isOpeningStep && !isShopOpen) {
            actions.setTutorialStep('SELL_ITEM_GUIDE');
            // 에너지가 부족할 수도 있는 극한 상황을 대비해 강제 실행 (reducer가 거부해도 호출은 함)
            actions.toggleShop();
            return;
        }

        actions.toggleShop();
    }, [isShopOpen, state.tutorialStep, actions]);

    const getThanksDialogue = useCallback(() => {
        const itemName = getItemName(activeCustomer?.request.requestedId || "");
        if (lastSoldQuality > 100) {
            return [
                `"Unbelievable! This ${itemName} is a true masterpiece. The edge is unlike anything I've seen. You really have the Lockhart touch!"`,
                `"Absolute perfection. I can feel the strength in this steel. I'll tell everyone in the tavern about your forge!"`,
                `"This quality is beyond what I expected. A fair price for legendary work. Thank you, Lockhart!"`
            ][Math.floor(Math.random() * 3)];
        } 
        if (lastSoldQuality < 80) {
            return [
                `"It'll do for now, I suppose. Though the finish on this ${itemName} is a bit rough... I hope your next work is a bit more refined."`,
                `"Hmm, not your best work, smith. I'll take it, but I was expecting that famous Lockhart quality. Try harder next time."`,
                `"A bit crude, but I need a blade today. Next time, I hope the anvil's rhythm is more precise."`
            ][Math.floor(Math.random() * 3)];
        }
        return [
            `"Fantastic craftsmanship! This ${itemName} is exactly what I needed. Thank you, Lockhart!"`,
            `"Superb work. I feel much safer with this by my side. I'll be back!"`,
            `"A fair price for quality steel. May your bellows never tire, smith."`,
            `"You truly have the Lockhart touch. This will serve me well in the ruins."`
        ][Math.floor(Math.random() * 4)];
    }, [activeCustomer, lastSoldQuality, getItemName]);

    const getRefusalDialogue = useCallback(() => {
        if (refusalReaction === 'POLITE') {
            return [
                `"I see. Perhaps another time then. Safe forging, smith."`,
                `"Ah, a shame. I'll keep looking elsewhere for now."`,
                `"Understandable. A Lockhart's work shouldn't be rushed. Farewell."`,
                `"I'll come back when your anvil is hotter. Until next time."`
            ][(activeCustomer?.id.length || 0) % 4];
        } else {
            return [
                `"What? I walked all this way for nothing? Hmph. Don't expect me back soon."`,
                `"A cold welcome for a paying customer... I'll find a better forge."`,
                `"Unbelievable. My old blade has more edge than your business sense!"`,
                `"I thought the Lockharts were more reliable. Guess I was wrong."`
            ][(activeCustomer?.id.length || 0) % 4];
        }
    }, [refusalReaction, activeCustomer]);

    const tutorialContent = useMemo(() => {
        if (tutorialStep === 'PIP_PRAISE_DIALOG') {
            return {
                speaker: activeCustomer?.mercenary.name || "Pip the Green",
                text: "This... this is incredible. I can feel the balance in the grip. It's much better than the scraps I found in the woods. You really are a Lockhart, aren't you?",
                options: [{ label: "Continue", action: () => actions.setTutorialStep('DRAGON_TALK_DIALOG'), variant: 'primary' as const }]
            };
        }
        if (tutorialStep === 'DRAGON_TALK_DIALOG') {
            return {
                speaker: activeCustomer?.mercenary.name || "Pip the Green",
                text: "The village... it hasn't been the same since the Dragon's fire. I lost my brother that night. I see that same shadow in your eyes, smith. We all lost someone. Good luck with the forge.",
                options: [{ label: "Farewell", action: () => { handleFarewell(); actions.setTutorialStep('TUTORIAL_END_DIALOG'); }, variant: 'primary' as const }]
            };
        }
        if (tutorialStep === 'TUTORIAL_END_DIALOG') {
            return {
                speaker: "Lockhart",
                text: "Finally... the first sale. It's a small spark, but enough to light the way. I'll reclaim our legacy, one blade at a time.",
                options: [{ label: "Complete Tutorial", action: () => actions.completeTutorial(), variant: 'primary' as const }]
            };
        }
        return null;
    }, [tutorialStep, activeCustomer, actions, handleFarewell]);

    const dialogueState = useMemo(() => {
        if (tutorialContent) return tutorialContent;
        if (!activeCustomer) return null;

        if (saleCompleted) {
            return {
                speaker: activeCustomer.mercenary.name,
                text: getThanksDialogue(),
                options: [{ label: "Farewell", action: handleFarewell, variant: 'neutral' as const }]
            };
        }

        if (refusalReaction) {
            return {
                speaker: activeCustomer.mercenary.name,
                text: getRefusalDialogue(),
                options: [{ label: "Farewell", action: handleFarewell, variant: 'neutral' as const }]
            };
        }

        const { request, mercenary } = activeCustomer;
        const inventoryMatch = matchingItems.length > 0;

        return {
            speaker: mercenary.name,
            text: request.dialogue,
            highlightTerm: getItemName(request.requestedId),
            itemDetail: {
                icon: '📦',
                imageUrl: globalGetAssetUrl(`${request.requestedId}.png`, 'equipments'),
                price: request.price,
                isUnlocked: true
            },
            options: [
                { 
                    label: `Sell (${request.price} G)`, 
                    action: handleSellClick, 
                    variant: 'primary' as const, 
                    disabled: !inventoryMatch 
                },
                { 
                    label: "Refuse", 
                    action: handleRefuse, 
                    variant: 'danger' as const 
                }
            ]
        };
    }, [activeCustomer, saleCompleted, refusalReaction, matchingItems, tutorialContent, getThanksDialogue, getRefusalDialogue, handleFarewell, handleSellClick, handleRefuse, getItemName]);

    return {
        state,
        actions,
        isShopOpen,
        activeCustomer,
        shopQueue,
        floatingHearts,
        saleCompleted,
        refusalReaction,
        dialogueState,
        matchingItems,
        showInstanceSelector,
        selectedInstance,
        isTutorialActive: !!tutorialStep,
        canAffordOpen: state.stats.energy >= GAME_CONFIG.ENERGY_COST.OPEN_SHOP,
        handlers: {
            handleToggleShop,
            handleFarewell,
            handleSellClick,
            handleRefuse,
            setShowInstanceSelector,
            setSelectedInstance,
            executeSell
        }
    };
};

import React, { useState, useEffect, useMemo, useRef, useCallback } from 'react';
import { useGame } from '../../context/GameContext';
import DialogueBox from '../DialogueBox';
import { getAssetUrl } from '../../utils';
import { TutorialSceneMode } from '../../types/game-state';
import { Flame, Zap, FastForward, Pointer } from 'lucide-react';
import ConfirmationModal from '../modals/ConfirmationModal';

const MAX_TEMP = 1500;
const IDLE_TEMP = 10;

type SequenceStep = 
    | 'IDLE' 
    | 'POST_REPLACE_TALK' 
    | 'WAIT_HEAT' 
    | 'HEAT_CONFIRM_DIALOG' 
    | 'WAIT_CONTINUE_BELLOWS' 
    | 'WAIT_PUMP' 
    | 'FURNACE_FINAL_DIALOG';

type TutorialDirection = 'top' | 'bottom' | 'left' | 'right' | 'topleft' | 'topright' | 'bottomleft' | 'bottomright';

interface SceneStepConfig {
    targetId: string;
    label: string;
    direction: TutorialDirection;
}

const SCENE_STEPS_CONFIG: Partial<Record<SequenceStep, SceneStepConfig>> = {
    WAIT_HEAT: { targetId: "tutorial-heat", label: "Ignite Furnace", direction: "left" },
    WAIT_PUMP: { targetId: "tutorial-bellows", label: "Pump Bellows", direction: "left" }
};

const SCRIPTS: Record<string, { text: string; options?: any[] }> = {
    PROLOGUE_0: { text: "The Lockhart forge lies in ashes, and my family is gone. But the fury in my blood burns hotter than any dragon's fire. I will rebuild." },
    PROLOGUE_1: { text: "The furnace is cold as death and beyond repair. I must head to the Market immediately to find a replacement and light the hearth once more." },

    FURNACE_0: { text: "The furnace is finally in place. The air in the forge doesn't feel so heavy and cold anymore." },
    FURNACE_1: { text: "It's a sturdy unit. I've managed to seal the connections, but I should check if the flue is drawing correctly. Striking the flint now..." },

    FURNACE_HEATED: { text: "The temperature is rising. The heat is building... the chimney is drawing well." },
    FURNACE_COOLING: { text: "The fire is settling down. I should use the bellows to keep the oxygen flowing." },
    FURNACE_BELLOWS_MONO: { text: "If the temperature drops below 400°C, the bellows won't be enough to bring it back to a roar. Pump it to the limit!" },

    FURNACE_MAXED: { text: "Magnificent. The forge is finally alive and roaring. I'm ready to begin the work of retribution." }
};

const LocalSpotlight = ({ step, hasPumpedOnce }: { step: SequenceStep, hasPumpedOnce: boolean }) => {
    const [targetRect, setTargetRect] = useState<DOMRect | null>(null);
    const [animatedRadius, setAnimatedRadius] = useState(2000);
    const requestRef = useRef<number | null>(null);
    const animRef = useRef<number | null>(null);
    const config = SCENE_STEPS_CONFIG[step];

    const updateRect = useCallback(() => {
        if (!config) return;
        const el = document.getElementById(config.targetId);
        if (el) {
            const rect = el.getBoundingClientRect();
            if (rect.width > 0 && rect.height > 0) {
                setTargetRect(rect);
            }
        }
        requestRef.current = requestAnimationFrame(updateRect);
    }, [config]);

    useEffect(() => {
        if (!targetRect) return;
        const targetR = Math.max(targetRect.width, targetRect.height) / 1.3;
        setAnimatedRadius(2000);
        const startTime = performance.now();
        const duration = 1300;
        const animate = (now: number) => {
            const elapsed = now - startTime;
            const progress = Math.min(elapsed / duration, 1);
            const easeOut = 1 - Math.pow(1 - progress, 3);
            const nextR = 2000 - (2000 - targetR) * easeOut;
            setAnimatedRadius(nextR);
            if (progress < 1) animRef.current = requestAnimationFrame(animate);
        };
        animRef.current = requestAnimationFrame(animate);
        return () => { if (animRef.current !== null) cancelAnimationFrame(animRef.current); };
    }, [step, !!targetRect]);

    useEffect(() => {
        requestRef.current = requestAnimationFrame(updateRect);
        return () => { if (requestRef.current !== null) cancelAnimationFrame(requestRef.current); };
    }, [updateRect]);

    if (!config || !targetRect) return null;

    const { top, left, width, height } = targetRect;
    const centerX = left + width / 2;
    const centerY = top + height / 2;

    let pointerStyles: React.CSSProperties = {};
    let iconRotation = '';
    let animationClass = '';
    let containerLayout = '';
    let labelMargin = '';

    const cardinalBuffer = 12;

    switch (config.direction) {
        case 'top':
            pointerStyles = { left: centerX, top: top - cardinalBuffer, transform: 'translate(-50%, -100%)' };
            iconRotation = 'rotate(180deg)';
            animationClass = 'animate-bounce-reverse';
            containerLayout = 'flex-col-reverse';
            labelMargin = 'mb-3';
            break;
        case 'bottom':
            pointerStyles = { left: centerX, top: top + height + cardinalBuffer, transform: 'translateX(-50%)' };
            iconRotation = '';
            animationClass = 'animate-bounce';
            containerLayout = 'flex-col';
            labelMargin = 'mt-3';
            break;
        case 'left':
            pointerStyles = { left: left - cardinalBuffer, top: centerY, transform: 'translate(-100%, -50%)' };
            iconRotation = 'rotate(90deg)';
            animationClass = 'animate-bounce-x-reverse';
            containerLayout = 'flex-row-reverse';
            labelMargin = 'mr-3';
            break;
        case 'right':
            pointerStyles = { left: left + width + cardinalBuffer, top: centerY, transform: 'translateY(-50%)' };
            iconRotation = 'rotate(-90deg)';
            animationClass = 'animate-bounce-x';
            containerLayout = 'flex-row';
            labelMargin = 'ml-3';
            break;
    }

    const currentLabel = (step === 'WAIT_PUMP' && hasPumpedOnce) ? "Keep Pump!" : config.label;

    return (
        <div className="fixed inset-0 z-[3050] pointer-events-none overflow-hidden">
            <svg className="absolute inset-0 w-full h-full pointer-events-none">
                <defs>
                    <mask id="tutorial-mask-local">
                        <rect width="100%" height="100%" fill="white" />
                        <circle cx={centerX} cy={centerY} r={animatedRadius} fill="black" />
                    </mask>
                </defs>
                <rect 
                    width="100%" 
                    height="100%" 
                    fill={`rgba(0,0,0,0.75)`} 
                    mask="url(#tutorial-mask-local)" 
                />
            </svg>

            {/* Click-blocking overlay around the target */}
            <div className="absolute inset-0 pointer-events-none">
                <div className="absolute top-0 left-0 w-full pointer-events-auto bg-transparent" style={{ height: top }} />
                <div className="absolute left-0 w-full pointer-events-auto bg-transparent" style={{ top: top + height, bottom: 0 }} />
                <div className="absolute top-0 left-0 pointer-events-auto bg-transparent" style={{ top, height, width: left }} />
                <div className="absolute top-0 pointer-events-auto bg-transparent" style={{ top, height, left: left + width, right: 0 }} />
            </div>

            <div 
                key={`${config.targetId}-${currentLabel}-${config.direction}`}
                className="absolute animate-in fade-in zoom-in-95 duration-300" 
                style={pointerStyles}
            >
                <div className={`flex items-center ${containerLayout} ${animationClass}`}>
                    <Pointer className={`w-8 h-8 md:w-12 md:h-12 text-amber-400 fill-amber-500/20 drop-shadow-[0_0_15px_rgba(245,158,11,0.8)]`} style={{ transform: iconRotation }} />
                    <div className={`${labelMargin} px-4 py-1.5 bg-amber-600 text-white text-[10px] md:text-xs font-black uppercase tracking-widest rounded-full shadow-2xl border-2 border-amber-400 whitespace-nowrap`}>
                        {currentLabel}
                    </div>
                </div>
            </div>
        </div>
    );
};

const TutorialScene: React.FC = () => {
    const { state, actions } = useGame();
    const [seq, setSeq] = useState<SequenceStep>('IDLE');
    const [currentStep, setCurrentStep] = useState(0);
    const [temp, setTemp] = useState(0); 
    const [isPumping, setIsPumping] = useState(false);
    const [hasPumpedOnce, setHasPumpedOnce] = useState(false);
    const [showFlash, setShowFlash] = useState(false);
    const [isStarted, setIsStarted] = useState(false);
    const [showSkipConfirm, setShowSkipConfirm] = useState(false);

    const mode = state.activeTutorialScene || 'PROLOGUE';

    // Reset internal state whenever the tutorial mode changes
    useEffect(() => {
        setIsStarted(false);
        setHasPumpedOnce(false);
        setTemp(0);
        setCurrentStep(0);
        setSeq('IDLE');
    }, [mode]);

    useEffect(() => {
        if (seq === 'HEAT_CONFIRM_DIALOG' || seq === 'WAIT_CONTINUE_BELLOWS' || seq === 'WAIT_PUMP') {
            const timer = setInterval(() => {
                setTemp(prev => {
                    const floorVal = 26.17;
                    if (prev > floorVal) return prev - 0.12;
                    return floorVal;
                });
            }, 50);
            return () => clearInterval(timer);
        }
    }, [seq]);

    const bgImage = useMemo(() => {
        if (mode === 'PROLOGUE' || (seq === 'IDLE' && !isStarted)) return 'tutorial/forge_ruined_bg.png';
        if (seq === 'POST_REPLACE_TALK' || seq === 'WAIT_HEAT') return 'tutorial/forge_fixed_bg.png';
        const currentDegrees = Math.round(IDLE_TEMP + (temp / 100) * (MAX_TEMP - IDLE_TEMP));
        if (currentDegrees >= 1490) return 'tutorial/forge_hot_bg.png';
        if (['HEAT_CONFIRM_DIALOG', 'WAIT_CONTINUE_BELLOWS', 'WAIT_PUMP', 'FURNACE_FINAL_DIALOG'].includes(seq)) return 'tutorial/forge_start_bg.png';
        return 'tutorial/forge_fixed_bg.png';
    }, [mode, seq, temp, isStarted]);

    const handleStart = () => {
        if (isStarted) return;
        if (mode === 'FURNACE_RESTORED') {
            setShowFlash(true);
            setTimeout(() => {
                setIsStarted(true);
                setSeq('POST_REPLACE_TALK');
                setCurrentStep(0);
            }, 50);
            setTimeout(() => setShowFlash(false), 800);
        } else {
            setIsStarted(true);
        }
    };

    const handleHeatUp = () => {
        if (seq !== 'WAIT_HEAT') return;
        setTemp(39.6);
        setSeq('HEAT_CONFIRM_DIALOG');
    };

    const handlePump = () => {
        setIsPumping(true);
        setHasPumpedOnce(true);
        const nextTempRatio = Math.min(100, temp + 5.5);
        setTemp(nextTempRatio);
        setTimeout(() => setIsPumping(false), 300);

        if (seq === 'WAIT_PUMP' && nextTempRatio >= 99) {
            setSeq('FURNACE_FINAL_DIALOG');
        }
    };

    const dialogue = useMemo(() => {
        if (!isStarted) return { text: "" };
        if (mode === 'PROLOGUE') return SCRIPTS[`PROLOGUE_${currentStep}`];
        if (seq === 'POST_REPLACE_TALK') return SCRIPTS[`FURNACE_${currentStep}`];
        if (seq === 'HEAT_CONFIRM_DIALOG') return SCRIPTS.FURNACE_HEATED;
        if (seq === 'WAIT_CONTINUE_BELLOWS') {
            return currentStep === 0 ? SCRIPTS.FURNACE_COOLING : SCRIPTS.FURNACE_BELLOWS_MONO;
        }
        if (seq === 'FURNACE_FINAL_DIALOG') return SCRIPTS.FURNACE_MAXED;
        return { text: "..." };
    }, [isStarted, mode, currentStep, seq]);

    const handleNext = () => {
        if (mode === 'PROLOGUE') {
            if (currentStep < 1) setCurrentStep(prev => prev + 1);
            else actions.completePrologue();
        } else {
            if (seq === 'POST_REPLACE_TALK') {
                if (currentStep < 1) setCurrentStep(prev => prev + 1);
                else setSeq('WAIT_HEAT');
            } else if (seq === 'HEAT_CONFIRM_DIALOG') {
                setSeq('WAIT_CONTINUE_BELLOWS');
                setCurrentStep(0);
            } else if (seq === 'WAIT_CONTINUE_BELLOWS') {
                if (currentStep < 1) setCurrentStep(prev => prev + 1);
                else setSeq('WAIT_PUMP');
            } else if (seq === 'FURNACE_FINAL_DIALOG') {
                actions.setTutorialScene('SMITHING');
                actions.setTutorialStep('CRAFT_START_DIALOG');
            }
        }
    };

    const handleConfirmSkip = () => {
        actions.completeTutorial();
        setShowSkipConfirm(false);
    };

    const promptText = mode === 'FURNACE_RESTORED' ? "REPLACE FURNACE" : "TAP TO BEGIN";

    // 지시 단계(Spotlight가 활성화되는 단계)인지 확인
    const isIndicateStep = seq === 'WAIT_HEAT' || seq === 'WAIT_PUMP';

    return (
        <div className="fixed inset-0 z-[3000] bg-stone-950 overflow-hidden flex flex-col items-center justify-center cursor-pointer px-safe" onClick={handleStart}>
            <style>{`
                @keyframes bounce-x { 0%, 100% { transform: translateX(0); } 50% { transform: translateX(12px); } }
                @keyframes bounce-x-reverse { 0%, 100% { transform: translateX(0); } 50% { transform: translateX(-12px); } }
                @keyframes bounce-reverse { 0%, 100% { transform: translateY(0); } 50% { transform: translateY(-12px); } }
                .animate-bounce-x { animation: bounce-x 1s infinite; }
                .animate-bounce-x-reverse { animation: bounce-x-reverse 1s infinite; }
                .animate-bounce-reverse { animation: bounce-reverse 1s infinite; }
                @keyframes flash-out { 0% { opacity: 0; } 20% { opacity: 1; } 100% { opacity: 0; } }
                .animate-flash-out { animation: flash-out 0.8s ease-out forwards; }
            `}</style>

            <div className="absolute inset-0 z-0 pointer-events-none">
                <img src={getAssetUrl(bgImage)} className="w-full h-full object-cover opacity-80" alt="Background" />
                <div className="absolute inset-0 bg-black/30"></div>
            </div>

            <div className="absolute top-4 right-4 z-[6000]">
                <button onClick={(e) => { e.stopPropagation(); setShowSkipConfirm(true); }} className="flex items-center gap-1.5 px-3 py-1.5 bg-stone-900/90 hover:bg-stone-800 border border-stone-700 text-stone-300 rounded-full text-[10px] font-black uppercase shadow-2xl backdrop-blur-md transition-all active:scale-95 group">
                    <FastForward className="w-3 h-3 group-hover:animate-pulse" /> Skip Tutorial
                </button>
            </div>

            {showFlash && <div className="absolute inset-0 z-[4000] bg-white animate-flash-out pointer-events-none"></div>}

            {!isStarted && !showFlash && (
                <div className="relative z-20 flex flex-col items-center animate-pulse pointer-events-none">
                    <span className="text-amber-500 font-black uppercase tracking-[0.4em] text-[10px] md:text-sm drop-shadow-[0_0_15px_rgba(245,158,11,0.6)]">{promptText}</span>
                </div>
            )}

            {isStarted && isIndicateStep && (
                <LocalSpotlight step={seq} hasPumpedOnce={hasPumpedOnce} />
            )}

            {/* 다이얼로그는 지시 단계가 아닐 때만 렌더링 (설명 -> 클릭 -> 다이얼로그 숨김 -> 인터랙션 지시) */}
            {isStarted && !isIndicateStep && (
                <div className="absolute bottom-6 md:bottom-12 left-1/2 -translate-x-1/2 w-[92vw] md:w-[85vw] max-w-5xl pointer-events-auto z-[5000]">
                    <DialogueBox 
                        speaker={mode === 'PROLOGUE' || seq !== 'FURNACE_FINAL_DIALOG' ? "Lockhart" : "Master Smith"} 
                        text={dialogue.text} 
                        options={[{ label: "Continue", action: handleNext, variant: 'primary' }]} 
                        className="w-full relative" 
                    />
                </div>
            )}

            {mode === 'FURNACE_RESTORED' && isStarted && (
                <div className="absolute top-[15dvh] right-[5vw] z-[3040] flex flex-col items-center gap-6 animate-in slide-in-from-right-8 duration-700 pointer-events-auto">
                    <div className="flex flex-col items-center">
                        <span className="text-[10px] font-black text-stone-300 uppercase tracking-tighter mb-2 font-mono drop-shadow-md">
                            {Math.round(IDLE_TEMP + (temp / 100) * (MAX_TEMP - IDLE_TEMP))}°C
                        </span>
                        <div className="w-7 h-48 md:h-64 bg-stone-950 rounded-full border-2 border-stone-800 relative shadow-2xl overflow-hidden">
                            <div className="absolute inset-1 rounded-full overflow-hidden">
                                <div className={`absolute bottom-0 left-0 right-0 rounded-full transition-all duration-300 ${temp < 30 ? 'bg-blue-600' : temp > 80 ? 'bg-red-600 animate-pulse' : 'bg-amber-500'}`} style={{ height: `${temp}%` }} />
                            </div>
                        </div>
                    </div>

                    <button id="tutorial-bellows" onClick={(e) => { e.stopPropagation(); handlePump(); }} disabled={seq !== 'WAIT_PUMP'} className={`w-16 h-16 md:w-24 md:h-24 rounded-full border-4 flex flex-col items-center justify-center transition-all shadow-2xl relative overflow-hidden group ${seq === 'WAIT_PUMP' ? 'bg-stone-800 border-amber-500 animate-pulse' : 'bg-stone-900 border-stone-800 grayscale opacity-40'} ${isPumping ? 'scale-90 brightness-150' : 'hover:scale-105'}`}>
                        <Zap className={`w-6 h-6 md:w-10 md:h-10 ${seq === 'WAIT_PUMP' ? 'text-amber-400' : 'text-stone-600'}`} />
                        <span className="text-[8px] md:text-[10px] font-black uppercase tracking-tighter mt-1">Pump</span>
                    </button>

                    <button id="tutorial-heat" onClick={(e) => { e.stopPropagation(); handleHeatUp(); }} disabled={seq !== 'WAIT_HEAT'} className={`w-14 h-14 md:w-20 md:h-20 rounded-xl border-2 flex flex-col items-center justify-center transition-all shadow-2xl ${seq === 'WAIT_HEAT' ? 'bg-orange-900/60 border-orange-500 shadow-orange-500/20' : 'bg-stone-900 border-stone-800 grayscale opacity-40'}`}>
                        <Flame className={`w-5 h-5 md:w-8 md:h-8 ${seq === 'WAIT_HEAT' ? 'text-orange-400' : 'text-stone-600'}`} />
                        <span className="text-[7px] md:text-[9px] font-black uppercase tracking-widest mt-1">Ignite</span>
                    </button>
                </div>
            )}

            <ConfirmationModal isOpen={showSkipConfirm} title="Skip Tutorial?" message="Are you sure you want to skip the introduction and go straight to the forge? All basic systems will be unlocked." confirmLabel="Skip Everything" onConfirm={handleConfirmSkip} onCancel={() => setShowSkipConfirm(false)} isDanger={true} />
        </div>
    );
};

export default TutorialScene;

import { useState, useEffect, useCallback, useMemo } from 'react';
import { useGame } from '../../../../context/GameContext';
import { EQUIPMENT_ITEMS } from '../../../../data/equipment';
import { materials } from '../../../../data/materials';
import { GAME_CONFIG } from '../../../../config/game-config';
import { InventoryItem } from '../../../../types/inventory';
import { getAssetUrl as globalGetAssetUrl } from '../../../../utils';

interface FloatingHeart {
    id: number;
    left: number;
    delay: number;
    size: number;
}

export const useShop = () => {
    const { state, actions } = useGame();
    const { isShopOpen } = state.forge;
    const { activeCustomer, shopQueue, tutorialStep, inventory } = state;

    const [floatingHearts, setFloatingHearts] = useState<FloatingHeart[]>([]);
    const [saleCompleted, setSaleCompleted] = useState(false);
    const [lastSoldQuality, setLastSoldQuality] = useState<number>(100);
    const [refusalReaction, setRefusalReaction] = useState<'POLITE' | 'ANGRY' | null>(null);
    const [showInstanceSelector, setShowInstanceSelector] = useState(false);
    const [selectedInstance, setSelectedInstance] = useState<InventoryItem | null>(null);

    useEffect(() => {
        if (!activeCustomer) {
            setSaleCompleted(false);
            setRefusalReaction(null);
            setShowInstanceSelector(false);
            setSelectedInstance(null);
        }
    }, [activeCustomer]);

    const spawnHearts = useCallback((count: number) => {
        const newHearts = Array.from({ length: count }).map((_, i) => ({
            id: Date.now() + i,
            left: 40 + Math.random() * 20,
            delay: Math.random() * 0.5,
            size: 16 + Math.random() * 12
        }));
        setFloatingHearts(prev => [...prev, ...newHearts]);
        setTimeout(() => setFloatingHearts([]), 3500);
    }, []);

    const getItemName = useCallback((id: string) => {
        const eq = EQUIPMENT_ITEMS.find(e => e.id === id);
        if (eq) return eq.name;
        const res = Object.values(materials).find(i => i.id === id);
        return res ? res.name : id;
    }, []);

    const matchingItems = useMemo(() => {
        if (!activeCustomer) return [];
        const { request } = activeCustomer;
        if (request.type === 'RESOURCE') {
            return inventory.filter(i => i.id === request.requestedId);
        } else {
            return inventory.filter(i => i.id.startsWith(request.requestedId));
        }
    }, [activeCustomer, inventory]);

    const executeSell = useCallback((item: InventoryItem) => {
        if (!activeCustomer || !item) return;
        if (item.isLocked) {
            actions.showToast("Item is locked and cannot be sold.");
            return;
        }
        const { mercenary, request } = activeCustomer;
        const isPipTutorial = tutorialStep === 'SELL_ITEM_GUIDE' && mercenary.id === 'pip_green';

        const itemQuality = item.equipmentData?.quality || 100;
        setLastSoldQuality(itemQuality);

        let affinityGain = isPipTutorial ? 10 : 2;
        if (itemQuality > 100) affinityGain += 2;
        else if (itemQuality < 80) affinityGain = Math.max(1, affinityGain - 1);

        const markup = request.markup || 1.25;
        const finalPrice = Math.ceil(item.baseValue * markup);

        if (item.type === 'RESOURCE') {
            actions.sellItem(item.id, 1, finalPrice, undefined, mercenary);
        } else {
            actions.sellItem(item.id, 1, finalPrice, item.id, mercenary);
        }

        spawnHearts(affinityGain);
        setSaleCompleted(true);
        setShowInstanceSelector(false);
        setSelectedInstance(null);
    }, [activeCustomer, tutorialStep, actions, spawnHearts]);

    const handleSellClick = useCallback(() => {
        if (!activeCustomer) return;
        if (matchingItems.length > 1) {
            setShowInstanceSelector(true);
        } else if (matchingItems.length === 1) {
            executeSell(matchingItems[0]);
        }
    }, [activeCustomer, matchingItems, executeSell]);

    const handleRefuse = useCallback(() => {
        if (!activeCustomer) return;
        const { mercenary } = activeCustomer;
        const affinity = mercenary.affinity || 0;
        const politeChance = affinity > 40 ? 0.8 : 0.3;
        const isPolite = Math.random() < politeChance;
        if (isPolite) {
            setRefusalReaction('POLITE');
            actions.refuseCustomer(mercenary.id, 0);
        } else {
            setRefusalReaction('ANGRY');
            actions.refuseCustomer(mercenary.id, 5);
        }
    }, [activeCustomer, actions]);

    const handleFarewell = useCallback(() => {
        setSaleCompleted(false);
        setRefusalReaction(null);
        actions.dismissCustomer();
    }, [actions]);

    const handleToggleShop = useCallback(() => {
        const isOpeningStep = state.tutorialStep === 'OPEN_SHOP_SIGN_GUIDE';

        // 튜토리얼 중이고 아직 상점이 닫힌 상태라면 무조건 열 수 있도록 유도
        if (isOpeningStep && !isShopOpen) {
            actions.setTutorialStep('SELL_ITEM_GUIDE');
            // 에너지가 부족할 수도 있는 극한 상황을 대비해 강제 실행 (reducer가 거부해도 호출은 함)
            actions.toggleShop();
            return;
        }

        actions.toggleShop();
    }, [isShopOpen, state.tutorialStep, actions]);

    const getThanksDialogue = useCallback(() => {
        const itemName = getItemName(activeCustomer?.request.requestedId || "");
        if (lastSoldQuality > 100) {
            return [
                `"Unbelievable! This ${itemName} is a true masterpiece. The edge is unlike anything I've seen. You really have the Lockhart touch!"`,
                `"Absolute perfection. I can feel the strength in this steel. I'll tell everyone in the tavern about your forge!"`,
                `"This quality is beyond what I expected. A fair price for legendary work. Thank you, Lockhart!"`
            ][Math.floor(Math.random() * 3)];
        } 
        if (lastSoldQuality < 80) {
            return [
                `"It'll do for now, I suppose. Though the finish on this ${itemName} is a bit rough... I hope your next work is a bit more refined."`,
                `"Hmm, not your best work, smith. I'll take it, but I was expecting that famous Lockhart quality. Try harder next time."`,
                `"A bit crude, but I need a blade today. Next time, I hope the anvil's rhythm is more precise."`
            ][Math.floor(Math.random() * 3)];
        }
        return [
            `"Fantastic craftsmanship! This ${itemName} is exactly what I needed. Thank you, Lockhart!"`,
            `"Superb work. I feel much safer with this by my side. I'll be back!"`,
            `"A fair price for quality steel. May your bellows never tire, smith."`,
            `"You truly have the Lockhart touch. This will serve me well in the ruins."`
        ][Math.floor(Math.random() * 4)];
    }, [activeCustomer, lastSoldQuality, getItemName]);

    const getRefusalDialogue = useCallback(() => {
        if (refusalReaction === 'POLITE') {
            return [
                `"I see. Perhaps another time then. Safe forging, smith."`,
                `"Ah, a shame. I'll keep looking elsewhere for now."`,
                `"Understandable. A Lockhart's work shouldn't be rushed. Farewell."`,
                `"I'll come back when your anvil is hotter. Until next time."`
            ][(activeCustomer?.id.length || 0) % 4];
        } else {
            return [
                `"What? I walked all this way for nothing? Hmph. Don't expect me back soon."`,
                `"A cold welcome for a paying customer... I'll find a better forge."`,
                `"Unbelievable. My old blade has more edge than your business sense!"`,
                `"I thought the Lockharts were more reliable. Guess I was wrong."`
            ][(activeCustomer?.id.length || 0) % 4];
        }
    }, [refusalReaction, activeCustomer]);

    const tutorialContent = useMemo(() => {
        if (tutorialStep === 'PIP_PRAISE_DIALOG') {
            return {
                speaker: activeCustomer?.mercenary.name || "Pip the Green",
                text: "This... this is incredible. I can feel the balance in the grip. It's much better than the scraps I found in the woods. You really are a Lockhart, aren't you?",
                options: [{ label: "Continue", action: () => actions.setTutorialStep('DRAGON_TALK_DIALOG'), variant: 'primary' as const }]
            };
        }
        if (tutorialStep === 'DRAGON_TALK_DIALOG') {
            return {
                speaker: activeCustomer?.mercenary.name || "Pip the Green",
                text: "The village... it hasn't been the same since the Dragon's fire. I lost my brother that night. I see that same shadow in your eyes, smith. We all lost someone. Good luck with the forge.",
                options: [{ label: "Farewell", action: () => { handleFarewell(); actions.setTutorialStep('TUTORIAL_END_DIALOG'); }, variant: 'primary' as const }]
            };
        }
        if (tutorialStep === 'TUTORIAL_END_DIALOG') {
            return {
                speaker: "Lockhart",
                text: "Finally... the first sale. It's a small spark, but enough to light the way. I'll reclaim our legacy, one blade at a time.",
                options: [{ label: "Complete Tutorial", action: () => actions.completeTutorial(), variant: 'primary' as const }]
            };
        }
        return null;
    }, [tutorialStep, activeCustomer, actions, handleFarewell]);

    const dialogueState = useMemo(() => {
        if (tutorialContent) return tutorialContent;
        if (!activeCustomer) return null;

        if (saleCompleted) {
            return {
                speaker: activeCustomer.mercenary.name,
                text: getThanksDialogue(),
                options: [{ label: "Farewell", action: handleFarewell, variant: 'neutral' as const }]
            };
        }

        if (refusalReaction) {
            return {
                speaker: activeCustomer.mercenary.name,
                text: getRefusalDialogue(),
                options: [{ label: "Farewell", action: handleFarewell, variant: 'neutral' as const }]
            };
        }

        const { request, mercenary } = activeCustomer;
        const inventoryMatch = matchingItems.length > 0;

        // 아이템 정보 보완 (툴팁용)
        const isEquip = request.type === 'EQUIPMENT';
        const recipe = isEquip ? EQUIPMENT_ITEMS.find(e => e.id === request.requestedId) : null;
        const material = !isEquip ? Object.values(materials).find(m => m.id === request.requestedId) : null;
        const folder = isEquip ? 'equipments' : 'materials';

        return {
            speaker: mercenary.name,
            text: request.dialogue,
            highlightTerm: getItemName(request.requestedId),
            itemDetail: {
                icon: isEquip ? (recipe?.icon || '⚔️') : (material?.icon || '📦'),
                imageUrl: globalGetAssetUrl(`${request.requestedId}.png`, folder),
                price: request.price,
                requirements: recipe?.requirements, // 제작 재료 추가
                isUnlocked: true
            },
            options: [
                { 
                    label: `Sell (${request.price} G)`, 
                    action: handleSellClick, 
                    variant: 'primary' as const, 
                    disabled: !inventoryMatch 
                },
                { 
                    label: "Refuse", 
                    action: handleRefuse, 
                    variant: 'danger' as const 
                }
            ]
        };
    }, [activeCustomer, saleCompleted, refusalReaction, matchingItems, tutorialContent, getThanksDialogue, getRefusalDialogue, handleFarewell, handleSellClick, handleRefuse, getItemName]);

    return {
        state,
        actions,
        isShopOpen,
        activeCustomer,
        shopQueue,
        floatingHearts,
        saleCompleted,
        refusalReaction,
        dialogueState,
        matchingItems,
        showInstanceSelector,
        selectedInstance,
        isTutorialActive: !!tutorialStep,
        canAffordOpen: state.stats.energy >= GAME_CONFIG.ENERGY_COST.OPEN_SHOP,
        handlers: {
            handleToggleShop,
            handleFarewell,
            handleSellClick,
            handleRefuse,
            setShowInstanceSelector,
            setSelectedInstance,
            executeSell
        }
    };
};

import React, { useState, useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import { User, ChevronRight, Coins, Package, Lock } from 'lucide-react';
import { useGame } from '../context/GameContext';
import { materials } from '../data/materials';

interface DialogueOption {
  label: string;
  action: () => void;
  variant?: 'primary' | 'danger' | 'neutral';
  disabled?: boolean;
}

interface ItemDetail {
  icon: string;
  imageUrl?: string;
  price: number;
  requirements?: { id: string; count: number }[];
  isUnlocked?: boolean;
}

// Added speakerAvatar to DialogueBoxProps to resolve TS error in AssaultNavigator.tsx
interface DialogueBoxProps {
  speaker: string;
  text: string;
  options?: DialogueOption[];
  highlightTerm?: string;
  itemDetail?: ItemDetail;
  className?: string;
  speakerAvatar?: string;
}

const DialogueBox: React.FC<DialogueBoxProps> = ({ 
  speaker, 
  text, 
  options = [], 
  highlightTerm,
  itemDetail,
  className = "relative w-full z-40",
  speakerAvatar // Destructure speakerAvatar prop
}) => {
  const { state } = useGame();
  const [displayedIndex, setDisplayedIndex] = useState(0);
  const [isTyping, setIsTyping] = useState(false);
  const [showItemTooltip, setShowItemTooltip] = useState(false);
  const [tooltipCoords, setTooltipCoords] = useState({ x: 0, y: 0 });

  const isMounted = useRef(true);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const textContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    isMounted.current = true;
    return () => { 
      isMounted.current = false;
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, []);

  useEffect(() => {
    if (textContainerRef.current) {
      const container = textContainerRef.current;
      const scrollHandle = requestAnimationFrame(() => {
