interface DialogueOption {
  label: string;
  action: () => void;
  variant?: 'primary' | 'danger' | 'neutral';
  disabled?: boolean;
}

interface ItemDetail {
  id?: string;
  itemType?: 'EQUIPMENT' | 'RESOURCE';
  icon: string;
  imageUrl?: string;
  price: number;
  requirements?: { id: string; count: number }[];
  isUnlocked?: boolean;
}

