/**
 * 툴팁 전용 아이템 이미지 컴포넌트
 * 공통 유틸리티 getAssetUrl을 사용하여 경로를 생성하고 에러 핸들링을 수행합니다.
 */
const TooltipItemImage: React.FC<{ item: ItemDetail }> = ({ item }) => {
    const isEquip = item.itemType === 'EQUIPMENT';
    const folder = isEquip ? 'equipments' : 'materials';
    const filename = item.id ? `${item.id}.png` : '';

    const [imgSrc, setImgSrc] = useState<string>(
        item.imageUrl || (filename ? getAssetUrl(filename, folder) : '')
    );

    const handleImgError = () => {
        // ID 기반 로드 실패 시 아이템 정의에 기록된 fallback 이미지 시도
        if (item.id && materials[item.id]?.image) {
            const fallback = getAssetUrl(materials[item.id]!.image!, folder);
            if (imgSrc !== fallback) {
                setImgSrc(fallback);
                return;
            }
        }
        // 최종 실패 시 null 처리 (아이콘이 대신 보임)
        setImgSrc('');
    };

    if (!imgSrc) return <span className="text-xl md:text-3xl">{item.icon}</span>;

    return (
        <img 
            src={imgSrc} 
            onError={handleImgError} 
            className="w-7 h-7 md:w-11 md:h-11 object-contain" 
            alt="item" 
        />
    );
};

