          <div 
            ref={textContainerRef}
            className={`flex-1 overflow-y-auto overflow-x-hidden custom-scrollbar pr-1 md:pr-2 mb-1 md:mb-2 min-h-0 ${isTyping ? 'typing-active' : ''}`}
            style={{ scrollBehavior: isTyping ? 'auto' : 'smooth' }}
          >
            <div 
              className="text-stone-50 leading-snug md:leading-relaxed font-medium drop-shadow-[0_2px_4px_rgba(0,0,0,0.5)] transition-opacity duration-300 break-words whitespace-pre-wrap"
              style={{ fontSize: 'clamp(0.9rem, 2.4dvh, 1.6rem)' }}
            >
              {renderFormattedText()}
            </div>
          </div>

          {!isTyping && options.length > 0 && (
            <div className="mt-auto pt-2 flex flex-wrap gap-1.5 md:gap-4 justify-end animate-in fade-in slide-in-from-right-4 pb-1 shrink-0">
              {options.map((option, idx) => (
                <button
                  key={idx}
                  onClick={(e) => { e.stopPropagation(); option.action(); }}
                  disabled={option.disabled}
                  className={`px-4 md:px-10 py-1.5 md:py-4 rounded-lg md:rounded-xl font-black text-[9px] md:text-sm flex items-center gap-1.5 md:gap-3 transition-all transform active:scale-95 border shadow-2xl ${
                    option.disabled 
                      ? 'bg-stone-800/40 text-stone-600 border-stone-700/30 cursor-not-allowed'
                      : option.variant === 'danger'
                        ? 'bg-red-900/60 text-red-50 border-red-800/50 hover:bg-red-700 hover:border-red-400'
                        : option.variant === 'neutral'
                            ? 'bg-stone-800/60 text-stone-100 border-stone-600 hover:bg-stone-750 hover:border-stone-400'
                            : 'bg-amber-700/80 text-white border-amber-500 hover:bg-amber-600 hover:border-amber-300 hover:shadow-amber-900/60'
                  }`}
                >
                  <span className="whitespace-nowrap">{option.label}</span>
                  {!option.disabled && <ChevronRight className="hidden xs:block w-2.5 md:w-5 h-2.5 md:h-5 opacity-70 group-hover:translate-x-1 transition-transform" />}
                </button>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default DialogueBox;

import { useState, useEffect, useCallback, useMemo } from 'react';
import { useGame } from '../../../../context/GameContext';
import { EQUIPMENT_ITEMS } from '../../../../data/equipment';
import { materials } from '../../../../data/materials';
import { GAME_CONFIG } from '../../../../config/game-config';
import { InventoryItem } from '../../../../types/inventory';
import { getAssetUrl as globalGetAssetUrl } from '../../../../utils';

interface FloatingHeart {
    id: number;
    left: number;
    delay: number;
    size: number;
}

export const useShop = () => {
    const { state, actions } = useGame();
    const { isShopOpen } = state.forge;
    const { activeCustomer, shopQueue, tutorialStep, inventory } = state;

    const [floatingHearts, setFloatingHearts] = useState<FloatingHeart[]>([]);
    const [saleCompleted, setSaleCompleted] = useState(false);
    const [lastSoldQuality, setLastSoldQuality] = useState<number>(100);
    const [refusalReaction, setRefusalReaction] = useState<'POLITE' | 'ANGRY' | null>(null);
    const [showInstanceSelector, setShowInstanceSelector] = useState(false);
    const [selectedInstance, setSelectedInstance] = useState<InventoryItem | null>(null);

    useEffect(() => {
        if (!activeCustomer) {
            setSaleCompleted(false);
            setRefusalReaction(null);
            setShowInstanceSelector(false);
            setSelectedInstance(null);
        }
    }, [activeCustomer]);

    const spawnHearts = useCallback((count: number) => {
        const newHearts = Array.from({ length: count }).map((_, i) => ({
            id: Date.now() + i,
            left: 40 + Math.random() * 20,
            delay: Math.random() * 0.5,
            size: 16 + Math.random() * 12
        }));
        setFloatingHearts(prev => [...prev, ...newHearts]);
        setTimeout(() => setFloatingHearts([]), 3500);
    }, []);

    const getItemName = useCallback((id: string) => {
        const eq = EQUIPMENT_ITEMS.find(e => e.id === id);
        if (eq) return eq.name;
        const res = Object.values(materials).find(i => i.id === id);
        return res ? res.name : id;
    }, []);

    const matchingItems = useMemo(() => {
        if (!activeCustomer) return [];
        const { request } = activeCustomer;
        if (request.type === 'RESOURCE') {
            return inventory.filter(i => i.id === request.requestedId);
        } else {
            return inventory.filter(i => i.id.startsWith(request.requestedId));
        }
    }, [activeCustomer, inventory]);

    const executeSell = useCallback((item: InventoryItem) => {
        if (!activeCustomer || !item) return;
        if (item.isLocked) {
            actions.showToast("Item is locked and cannot be sold.");
            return;
        }
        const { mercenary, request } = activeCustomer;
        const isPipTutorial = tutorialStep === 'SELL_ITEM_GUIDE' && mercenary.id === 'pip_green';

        const itemQuality = item.equipmentData?.quality || 100;
        setLastSoldQuality(itemQuality);

        let affinityGain = isPipTutorial ? 10 : 2;
        if (itemQuality > 100) affinityGain += 2;
        else if (itemQuality < 80) affinityGain = Math.max(1, affinityGain - 1);

        const markup = request.markup || 1.25;
        const finalPrice = Math.ceil(item.baseValue * markup);

        if (item.type === 'RESOURCE') {
            actions.sellItem(item.id, 1, finalPrice, undefined, mercenary);
        } else {
            actions.sellItem(item.id, 1, finalPrice, item.id, mercenary);
        }

        spawnHearts(affinityGain);
        setSaleCompleted(true);
        setShowInstanceSelector(false);
        setSelectedInstance(null);
    }, [activeCustomer, tutorialStep, actions, spawnHearts]);

    const handleSellClick = useCallback(() => {
        if (!activeCustomer) return;
        if (matchingItems.length > 1) {
            setShowInstanceSelector(true);
        } else if (matchingItems.length === 1) {
            executeSell(matchingItems[0]);
        }
    }, [activeCustomer, matchingItems, executeSell]);

    const handleRefuse = useCallback(() => {
        if (!activeCustomer) return;
        const { mercenary } = activeCustomer;
        const affinity = mercenary.affinity || 0;
        const politeChance = affinity > 40 ? 0.8 : 0.3;
        const isPolite = Math.random() < politeChance;
        if (isPolite) {
            setRefusalReaction('POLITE');
            actions.refuseCustomer(mercenary.id, 0);
        } else {
            setRefusalReaction('ANGRY');
            actions.refuseCustomer(mercenary.id, 5);
        }
    }, [activeCustomer, actions]);

    const handleFarewell = useCallback(() => {
        setSaleCompleted(false);
        setRefusalReaction(null);
        actions.dismissCustomer();
    }, [actions]);

    const handleToggleShop = useCallback(() => {
        const isOpeningStep = state.tutorialStep === 'OPEN_SHOP_SIGN_GUIDE';

        // 튜토리얼 중이고 아직 상점이 닫힌 상태라면 무조건 열 수 있도록 유도
        if (isOpeningStep && !isShopOpen) {
            actions.setTutorialStep('SELL_ITEM_GUIDE');
            // 에너지가 부족할 수도 있는 극한 상황을 대비해 강제 실행 (reducer가 거부해도 호출은 함)
            actions.toggleShop();
            return;
        }

        actions.toggleShop();
    }, [isShopOpen, state.tutorialStep, actions]);

    const getThanksDialogue = useCallback(() => {
        const itemName = getItemName(activeCustomer?.request.requestedId || "");
        if (lastSoldQuality > 100) {
            return [
                `"Unbelievable! This ${itemName} is a true masterpiece. The edge is unlike anything I've seen. You really have the Lockhart touch!"`,
                `"Absolute perfection. I can feel the strength in this steel. I'll tell everyone in the tavern about your forge!"`,
                `"This quality is beyond what I expected. A fair price for legendary work. Thank you, Lockhart!"`
            ][Math.floor(Math.random() * 3)];
        } 
        if (lastSoldQuality < 80) {
            return [
                `"It'll do for now, I suppose. Though the finish on this ${itemName} is a bit rough... I hope your next work is a bit more refined."`,
                `"Hmm, not your best work, smith. I'll take it, but I was expecting that famous Lockhart quality. Try harder next time."`,
                `"A bit crude, but I need a blade today. Next time, I hope the anvil's rhythm is more precise."`
            ][Math.floor(Math.random() * 3)];
        }
        return [
            `"Fantastic craftsmanship! This ${itemName} is exactly what I needed. Thank you, Lockhart!"`,
            `"Superb work. I feel much safer with this by my side. I'll be back!"`,
            `"A fair price for quality steel. May your bellows never tire, smith."`,
            `"You truly have the Lockhart touch. This will serve me well in the ruins."`
        ][Math.floor(Math.random() * 4)];
    }, [activeCustomer, lastSoldQuality, getItemName]);

    const getRefusalDialogue = useCallback(() => {
        if (refusalReaction === 'POLITE') {
            return [
                `"I see. Perhaps another time then. Safe forging, smith."`,
                `"Ah, a shame. I'll keep looking elsewhere for now."`,
                `"Understandable. A Lockhart's work shouldn't be rushed. Farewell."`,
                `"I'll come back when your anvil is hotter. Until next time."`
            ][(activeCustomer?.id.length || 0) % 4];
        } else {
            return [
                `"What? I walked all this way for nothing? Hmph. Don't expect me back soon."`,
                `"A cold welcome for a paying customer... I'll find a better forge."`,
                `"Unbelievable. My old blade has more edge than your business sense!"`,
                `"I thought the Lockharts were more reliable. Guess I was wrong."`
            ][(activeCustomer?.id.length || 0) % 4];
        }
    }, [refusalReaction, activeCustomer]);

    const tutorialContent = useMemo(() => {
        if (tutorialStep === 'PIP_PRAISE_DIALOG') {
            return {
                speaker: activeCustomer?.mercenary.name || "Pip the Green",
                text: "This... this is incredible. I can feel the balance in the grip. It's much better than the scraps I found in the woods. You really are a Lockhart, aren't you?",
                options: [{ label: "Continue", action: () => actions.setTutorialStep('DRAGON_TALK_DIALOG'), variant: 'primary' as const }]
            };
        }
        if (tutorialStep === 'DRAGON_TALK_DIALOG') {
            return {
                speaker: activeCustomer?.mercenary.name || "Pip the Green",
                text: "The village... it hasn't been the same since the Dragon's fire. I lost my brother that night. I see that same shadow in your eyes, smith. We all lost someone. Good luck with the forge.",
                options: [{ label: "Farewell", action: () => { handleFarewell(); actions.setTutorialStep('TUTORIAL_END_DIALOG'); }, variant: 'primary' as const }]
            };
        }
        if (tutorialStep === 'TUTORIAL_END_DIALOG') {
            return {
                speaker: "Lockhart",
                text: "Finally... the first sale. It's a small spark, but enough to light the way. I'll reclaim our legacy, one blade at a time.",
                options: [{ label: "Complete Tutorial", action: () => actions.completeTutorial(), variant: 'primary' as const }]
            };
        }
        return null;
    }, [tutorialStep, activeCustomer, actions, handleFarewell]);

    const dialogueState = useMemo(() => {
        if (tutorialContent) return tutorialContent;
        if (!activeCustomer) return null;

        if (saleCompleted) {
            return {
                speaker: activeCustomer.mercenary.name,
                text: getThanksDialogue(),
                options: [{ label: "Farewell", action: handleFarewell, variant: 'neutral' as const }]
            };
        }

        if (refusalReaction) {
            return {
                speaker: activeCustomer.mercenary.name,
                text: getRefusalDialogue(),
                options: [{ label: "Farewell", action: handleFarewell, variant: 'neutral' as const }]
            };
        }

        const { request, mercenary } = activeCustomer;
        const inventoryMatch = matchingItems.length > 0;

        // 아이템 정보 보완 (툴팁용)
        const isEquip = request.type === 'EQUIPMENT';
        const recipe = isEquip ? EQUIPMENT_ITEMS.find(e => e.id === request.requestedId) : null;
        const material = !isEquip ? Object.values(materials).find(m => m.id === request.requestedId) : null;

        return {
            speaker: mercenary.name,
            text: request.dialogue,
            highlightTerm: getItemName(request.requestedId),
            itemDetail: {
                id: request.requestedId, // ID 추가
                itemType: request.type, // 타입 추가
                icon: isEquip ? (recipe?.icon || '⚔️') : (material?.icon || '📦'),
                price: request.price,
                requirements: recipe?.requirements, // 제작 재료 추가
                isUnlocked: true
            },
            options: [
                { 
                    label: `Sell (${request.price} G)`, 
                    action: handleSellClick, 
                    variant: 'primary' as const, 
                    disabled: !inventoryMatch 
                },
                { 
                    label: "Refuse", 
                    action: handleRefuse, 
                    variant: 'danger' as const 
                }
            ]
        };
    }, [activeCustomer, saleCompleted, refusalReaction, matchingItems, tutorialContent, getThanksDialogue, getRefusalDialogue, handleFarewell, handleSellClick, handleRefuse, getItemName]);

    return {
        state,
        actions,
        isShopOpen,
        activeCustomer,
        shopQueue,
        floatingHearts,
        saleCompleted,
        refusalReaction,
        dialogueState,
        matchingItems,
        showInstanceSelector,
        selectedInstance,
        isTutorialActive: !!tutorialStep,
        canAffordOpen: state.stats.energy >= GAME_CONFIG.ENERGY_COST.OPEN_SHOP,
        handlers: {
            handleToggleShop,
            handleFarewell,
            handleSellClick,
            handleRefuse,
            setShowInstanceSelector,
            setSelectedInstance,
            executeSell
        }
    };
};

import React, { useState, useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import { User, ChevronRight, Coins, Package, Lock } from 'lucide-react';
import { useGame } from '../context/GameContext';
import { materials } from '../data/materials';
import { getAssetUrl } from '../utils';

interface DialogueOption {
  label: string;
  action: () => void;
  variant?: 'primary' | 'danger' | 'neutral';
  disabled?: boolean;
}

interface ItemDetail {
  id: string;
  icon: string;
  price: number;
  requirements?: { id: string; count: number }[];
  isUnlocked?: boolean;
}

// Added speakerAvatar to DialogueBoxProps to resolve TS error in AssaultNavigator.tsx
interface DialogueBoxProps {
  speaker: string;
  text: string;
  options?: DialogueOption[];
  highlightTerm?: string;
  itemDetail?: ItemDetail;
  className?: string;
  speakerAvatar?: string;
}

const DialogueBox: React.FC<DialogueBoxProps> = ({ 
  speaker, 
  text, 
  options = [], 
  highlightTerm,
  itemDetail,
  className = "relative w-full z-40",
  speakerAvatar // Destructure speakerAvatar prop
}) => {
  const { state } = useGame();
  const [displayedIndex, setDisplayedIndex] = useState(0);
  const [isTyping, setIsTyping] = useState(false);
  const [showItemTooltip, setShowItemTooltip] = useState(false);
  const [tooltipCoords, setTooltipCoords] = useState({ x: 0, y: 0 });
  const [imgError, setImgError] = useState(false);

  const isMounted = useRef(true);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const textContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    isMounted.current = true;
    return () => { 
      isMounted.current = false;
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, []);

  useEffect(() => {
    if (textContainerRef.current) {
      const container = textContainerRef.current;
      const scrollHandle = requestAnimationFrame(() => {
        container.scrollTop = container.scrollHeight;
      });
      return () => cancelAnimationFrame(scrollHandle);
    }
  }, [displayedIndex, text, isTyping]);

  useEffect(() => {
    if (timerRef.current) clearInterval(timerRef.current);

    setDisplayedIndex(0);
    setIsTyping(true);
    setShowItemTooltip(false);
    setImgError(false);
    let index = 0;
    const speed = 25; 

    timerRef.current = setInterval(() => {
      if (!isMounted.current) return;

      index++;
      if (index > text.length) {
        if (timerRef.current) clearInterval(timerRef.current);
        setIsTyping(false);
        setDisplayedIndex(text.length);
      } else {
        setDisplayedIndex(index);
      }
    }, speed);

    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [text]);

  const handleSkipTyping = () => {
    if (isTyping) {
      if (timerRef.current) clearInterval(timerRef.current);
      setDisplayedIndex(text.length);
      setIsTyping(false);
    }
  };

  const getInventoryCount = (id: string) => {
    return state.inventory.find(i => i.id === id)?.quantity || 0;
  };

  const updateTooltipPosition = (e: React.MouseEvent | React.TouchEvent) => {
    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    setTooltipCoords({
      x: rect.left + rect.width / 2,
      y: rect.top
    });
  };

  const renderFormattedText = () => {
    if (!highlightTerm) {
      return <span>{text.slice(0, displayedIndex)}</span>;
    }

    const parts = text.split(new RegExp(`(${highlightTerm})`, 'g'));
    let charCount = 0;

    return parts.map((part, i) => {
      const startChar = charCount;
      const endChar = charCount + part.length;
      charCount = endChar;

      const visibleCountInPart = Math.max(0, Math.min(part.length, displayedIndex - startChar));
      if (visibleCountInPart <= 0) return null;

      const visiblePart = part.slice(0, visibleCountInPart);

      if (part === highlightTerm) {
        return (
          <span 
            key={i} 
            className="text-amber-400 font-black underline decoration-amber-500/50 underline-offset-4 cursor-pointer relative inline-block pointer-events-auto"
            onClick={(e) => { 
                e.stopPropagation(); 
                updateTooltipPosition(e); 
                setShowItemTooltip(!showItemTooltip); 
            }}
          >
            {visiblePart}
          </span>
        );
      }

      return <React.Fragment key={i}>{visiblePart}</React.Fragment>;
    });
  };

  // Tooltip content rendered via Portal
  const tooltipElement = showItemTooltip && itemDetail && createPortal(
    <div 
      className="fixed z-[10000] pointer-events-none p-3 md:p-4 bg-stone-900/98 backdrop-blur-2xl border-2 border-stone-700 rounded-2xl shadow-[0_20px_50px_rgba(0,0,0,0.9)] w-[80vw] max-w-[240px] md:max-w-[320px] animate-in fade-in zoom-in-95 duration-200"
      style={{ 
        left: `${Math.max(130, Math.min(window.innerWidth - 130, tooltipCoords.x))}px`, 
        top: `${tooltipCoords.y - 10}px`,
        transform: 'translate(-50%, -100%)'
      }}
    >
      <div className="flex items-center gap-3 mb-2 md:mb-3 pb-2 md:pb-3 border-b border-white/10">
        <div className={`w-10 h-10 md:w-16 md:h-16 bg-stone-950 rounded-xl border-2 flex items-center justify-center shadow-inner shrink-0 overflow-hidden ${!itemDetail.isUnlocked ? 'border-amber-600/50' : 'border-stone-800'}`}>
          {!itemDetail.isUnlocked ? (
            <span className="text-2xl md:text-4xl font-serif text-amber-500 font-black animate-pulse">?</span>
          ) : (
            <>
              {!imgError ? (
                <img 
                  src={getAssetUrl(`${itemDetail.id}.png`, 'materials')} 
                  onError={() => setImgError(true)}
                  className="w-7 h-7 md:w-11 md:h-11 object-contain" 
                  alt="item" 
                />
              ) : (
                <span className="text-xl md:text-3xl">{itemDetail.icon}</span>
              )}
            </>
          )}
        </div>
        <div className="flex flex-col leading-none">
          <span className="text-[7px] md:text-[10px] text-stone-500 font-black uppercase tracking-widest mb-1">Price</span>
          <div className={`flex items-center gap-1 font-mono font-black text-xs md:text-xl ${!itemDetail.isUnlocked ? 'text-stone-600' : 'text-emerald-400'}`}>
            <Coins className="w-3 h-3 md:w-5 md:h-5" />
            {!itemDetail.isUnlocked ? '???,???' : itemDetail.price.toLocaleString()} G
          </div>
        </div>
      </div>

      <div className="space-y-2">
        <h5 className="text-[7px] md:text-[9px] font-black text-stone-500 uppercase tracking-widest flex items-center gap-1.5">
          <Package className="w-2 h-2 md:w-3 md:h-3" /> Required Materials
        </h5>

        <div className="grid gap-1">
          {itemDetail.requirements && itemDetail.requirements.length > 0 ? (
            itemDetail.requirements.map((req, idx) => {
              const isClue = idx === 0; // 첫 번째 재료만 단서로 노출
              const shouldShow = itemDetail.isUnlocked || isClue;

              if (!shouldShow) {
                return (
                  <div key={req.id} className="flex justify-between items-center text-[8px] md:text-xs opacity-40">
                    <span className="truncate mr-2 font-bold tracking-tight text-stone-600">
                      ???
                    </span>
                    <div className="flex items-center gap-1 shrink-0">
                      <span className="font-mono font-black text-stone-700">
                        ? / ?
                      </span>
                      <div className="w-1 h-1 rounded-full bg-stone-800" />
                    </div>
                  </div>
                );
              }

              const hasCount = getInventoryCount(req.id);
              const isEnough = hasCount >= req.count;
              const mat = Object.values(materials).find(m => m.id === req.id);

              return (
                <div key={req.id} className="flex justify-between items-center text-[8px] md:text-xs">
                  <span className={`truncate mr-2 font-bold tracking-tight ${isEnough ? 'text-stone-300' : 'text-red-400'}`}>
                    {mat?.name || req.id}
                  </span>
                  <div className="flex items-center gap-1 shrink-0">
                    <span className={`font-mono font-black ${isEnough ? 'text-stone-500' : 'text-red-500'}`}>
                      {hasCount}/{req.count}
                    </span>
                    <div className={`w-1 h-1 rounded-full ${isEnough ? 'bg-emerald-500 shadow-[0_0_4px_rgba(16,185,129,0.5)]' : 'bg-red-500 animate-pulse'}`} />
                  </div>
                </div>
              );
            })
          ) : (
            <div className="text-[8px] md:text-xs text-stone-600 italic">No specific requirements found.</div>
          )}
        </div>

        {!itemDetail.isUnlocked && (
          <div className="mt-2 pt-2 border-t border-white/5 flex flex-col items-center text-center">
            <div className="flex items-center gap-1.5 text-amber-600/80">
              <Lock className="w-2.5 h-2.5 md:w-3 md:h-3" />
              <span className="text-[6px] md:text-[8px] font-black uppercase tracking-widest">Locked Knowledge</span>
            </div>
          </div>
        )}
      </div>

      {/* Tooltip Arrow */}
      <div className="absolute top-full left-1/2 -translate-x-1/2 w-0 h-0 border-l-[8px] md:border-l-[12px] border-l-transparent border-r-[8px] md:border-r-[12px] border-r-transparent border-t-[8px] md:border-t-[12px] border-t-stone-900/98"></div>
    </div>,
    document.body
  );

  return (
    <div className={className} onClick={() => showItemTooltip && setShowItemTooltip(false)}>
      {tooltipElement}

      <div 
        className="w-full h-[22dvh] min-h-[120px] md:h-[28vh] md:min-h-[160px] bg-stone-950/25 backdrop-blur-3xl border border-white/10 md:border-2 rounded-2xl md:rounded-3xl shadow-[0_25px_70px_rgba(0,0,0,0.7)] flex flex-row overflow-hidden animate-in slide-in-from-bottom-8 fade-in duration-500 ring-1 ring-white/10"
      >
        <div className="bg-stone-900/20 p-2 md:p-6 border-r border-white/5 flex flex-col items-center gap-1 md:gap-4 w-20 md:w-48 shrink-0 justify-center">
          <div className="w-9 h-9 md:w-20 md:h-20 rounded-full bg-gradient-to-br from-amber-900/30 to-stone-800/40 border border-amber-600/30 flex items-center justify-center shadow-inner ring-1 ring-white/5 overflow-hidden">
             {/* Render speaker avatar if provided, otherwise use generic User icon */}
             {speakerAvatar ? (
               <img src={speakerAvatar} className="w-full h-full object-cover" alt={speaker} />
             ) : (
               <User className="w-5 h-5 md:w-10 md:h-10 text-amber-500/90 drop-shadow-[0_0_15px_rgba(245,158,11,0.5)]" />
             )}
          </div>
          <div className="flex flex-col items-center overflow-hidden w-full">
              <span className="font-black text-amber-50 text-[10px] md:text-xl text-center font-serif leading-tight tracking-tight drop-shadow-md truncate w-full px-1">
                {speaker}
              </span>
          </div>
        </div>

        <div 
          className="flex-1 p-2.5 md:p-8 relative flex flex-col min-h-0 bg-gradient-to-br from-white/5 to-transparent cursor-pointer"
          onClick={handleSkipTyping}
        >
          <div 
            ref={textContainerRef}
            className={`flex-1 overflow-y-auto overflow-x-hidden custom-scrollbar pr-1 md:pr-2 mb-1 md:mb-2 min-h-0 ${isTyping ? 'typing-active' : ''}`}
            style={{ scrollBehavior: isTyping ? 'auto' : 'smooth' }}
          >
            <div 
              className="text-stone-50 leading-snug md:leading-relaxed font-medium drop-shadow-[0_2px_4px_rgba(0,0,0,0.5)] transition-opacity duration-300 break-words whitespace-pre-wrap"
              style={{ fontSize: 'clamp(0.9rem, 2.4dvh, 1.6rem)' }}
            >
              {renderFormattedText()}
            </div>
          </div>

          {!isTyping && options.length > 0 && (
            <div className="mt-auto pt-2 flex flex-wrap gap-1.5 md:gap-4 justify-end animate-in fade-in slide-in-from-right-4 pb-1 shrink-0">
              {options.map((option, idx) => (
                <button
                  key={idx}
                  onClick={(e) => { e.stopPropagation(); option.action(); }}
                  disabled={option.disabled}
                  className={`px-4 md:px-10 py-1.5 md:py-4 rounded-lg md:rounded-xl font-black text-[9px] md:text-sm flex items-center gap-1.5 md:gap-3 transition-all transform active:scale-95 border shadow-2xl ${
                    option.disabled 
                      ? 'bg-stone-800/40 text-stone-600 border-stone-700/30 cursor-not-allowed'
                      : option.variant === 'danger'
                        ? 'bg-red-900/60 text-red-50 border-red-800/50 hover:bg-red-700 hover:border-red-400'
                        : option.variant === 'neutral'
                            ? 'bg-stone-800/60 text-stone-100 border-stone-600 hover:bg-stone-750 hover:border-stone-400'
                            : 'bg-amber-700/80 text-white border-amber-500 hover:bg-amber-600 hover:border-amber-300 hover:shadow-amber-900/60'
                  }`}
                >
                  <span className="whitespace-nowrap">{option.label}</span>
                  {!option.disabled && <ChevronRight className="hidden xs:block w-2.5 md:w-5 h-2.5 md:h-5 opacity-70 group-hover:translate-x-1 transition-transform" />}
                </button>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default DialogueBox;

import { useState, useEffect, useCallback, useMemo } from 'react';
import { useGame } from '../../../../context/GameContext';
import { EQUIPMENT_ITEMS } from '../../../../data/equipment';
import { materials } from '../../../../data/materials';
import { GAME_CONFIG } from '../../../../config/game-config';
import { InventoryItem } from '../../../../types/inventory';
import { getAssetUrl as globalGetAssetUrl } from '../../../../utils';

interface FloatingHeart {
    id: number;
    left: number;
    delay: number;
    size: number;
}

export const useShop = () => {
    const { state, actions } = useGame();
    const { isShopOpen } = state.forge;
    const { activeCustomer, shopQueue, tutorialStep, inventory } = state;

    const [floatingHearts, setFloatingHearts] = useState<FloatingHeart[]>([]);
    const [saleCompleted, setSaleCompleted] = useState(false);
    const [lastSoldQuality, setLastSoldQuality] = useState<number>(100);
    const [refusalReaction, setRefusalReaction] = useState<'POLITE' | 'ANGRY' | null>(null);
    const [showInstanceSelector, setShowInstanceSelector] = useState(false);
    const [selectedInstance, setSelectedInstance] = useState<InventoryItem | null>(null);

    useEffect(() => {
        if (!activeCustomer) {
            setSaleCompleted(false);
            setRefusalReaction(null);
            setShowInstanceSelector(false);
            setSelectedInstance(null);
        }
    }, [activeCustomer]);

    const spawnHearts = useCallback((count: number) => {
        const newHearts = Array.from({ length: count }).map((_, i) => ({
            id: Date.now() + i,
            left: 40 + Math.random() * 20,
            delay: Math.random() * 0.5,
            size: 16 + Math.random() * 12
        }));
        setFloatingHearts(prev => [...prev, ...newHearts]);
        setTimeout(() => setFloatingHearts([]), 3500);
    }, []);

    const getItemName = useCallback((id: string) => {
        const eq = EQUIPMENT_ITEMS.find(e => e.id === id);
        if (eq) return eq.name;
        const res = Object.values(materials).find(i => i.id === id);
        return res ? res.name : id;
    }, []);

    const matchingItems = useMemo(() => {
        if (!activeCustomer) return [];
        const { request } = activeCustomer;
        if (request.type === 'RESOURCE') {
            return inventory.filter(i => i.id === request.requestedId);
        } else {
            return inventory.filter(i => i.id.startsWith(request.requestedId));
        }
    }, [activeCustomer, inventory]);

    const executeSell = useCallback((item: InventoryItem) => {
        if (!activeCustomer || !item) return;
        if (item.isLocked) {
            actions.showToast("Item is locked and cannot be sold.");
            return;
        }
        const { mercenary, request } = activeCustomer;
        const isPipTutorial = tutorialStep === 'SELL_ITEM_GUIDE' && mercenary.id === 'pip_green';

        const itemQuality = item.equipmentData?.quality || 100;
        setLastSoldQuality(itemQuality);

        let affinityGain = isPipTutorial ? 10 : 2;
        if (itemQuality > 100) affinityGain += 2;
        else if (itemQuality < 80) affinityGain = Math.max(1, affinityGain - 1);

        const markup = request.markup || 1.25;
        const finalPrice = Math.ceil(item.baseValue * markup);

        if (item.type === 'RESOURCE') {
            actions.sellItem(item.id, 1, finalPrice, undefined, mercenary);
        } else {
            actions.sellItem(item.id, 1, finalPrice, item.id, mercenary);
        }

        spawnHearts(affinityGain);
        setSaleCompleted(true);
        setShowInstanceSelector(false);
        setSelectedInstance(null);
    }, [activeCustomer, tutorialStep, actions, spawnHearts]);

    const handleSellClick = useCallback(() => {
        if (!activeCustomer) return;
        if (matchingItems.length > 1) {
            setShowInstanceSelector(true);
        } else if (matchingItems.length === 1) {
            executeSell(matchingItems[0]);
        }
    }, [activeCustomer, matchingItems, executeSell]);

    const handleRefuse = useCallback(() => {
        if (!activeCustomer) return;
        const { mercenary } = activeCustomer;
        const affinity = mercenary.affinity || 0;
        const politeChance = affinity > 40 ? 0.8 : 0.3;
        const isPolite = Math.random() < politeChance;
        if (isPolite) {
            setRefusalReaction('POLITE');
            actions.refuseCustomer(mercenary.id, 0);
        } else {
            setRefusalReaction('ANGRY');
            actions.refuseCustomer(mercenary.id, 5);
        }
    }, [activeCustomer, actions]);

    const handleFarewell = useCallback(() => {
        setSaleCompleted(false);
        setRefusalReaction(null);
        actions.dismissCustomer();
    }, [actions]);

    const handleToggleShop = useCallback(() => {
        const isOpeningStep = state.tutorialStep === 'OPEN_SHOP_SIGN_GUIDE';

        // 튜토리얼 중이고 아직 상점이 닫힌 상태라면 무조건 열 수 있도록 유도
        if (isOpeningStep && !isShopOpen) {
            actions.setTutorialStep('SELL_ITEM_GUIDE');
            // 에너지가 부족할 수도 있는 극한 상황을 대비해 강제 실행 (reducer가 거부해도 호출은 함)
            actions.toggleShop();
            return;
        }

        actions.toggleShop();
    }, [isShopOpen, state.tutorialStep, actions]);

    const getThanksDialogue = useCallback(() => {
        const itemName = getItemName(activeCustomer?.request.requestedId || "");
        if (lastSoldQuality > 100) {
            return [
                `"Unbelievable! This ${itemName} is a true masterpiece. The edge is unlike anything I've seen. You really have the Lockhart touch!"`,
                `"Absolute perfection. I can feel the strength in this steel. I'll tell everyone in the tavern about your forge!"`,
                `"This quality is beyond what I expected. A fair price for legendary work. Thank you, Lockhart!"`
            ][Math.floor(Math.random() * 3)];
        } 
        if (lastSoldQuality < 80) {
            return [
                `"It'll do for now, I suppose. Though the finish on this ${itemName} is a bit rough... I hope your next work is a bit more refined."`,
                `"Hmm, not your best work, smith. I'll take it, but I was expecting that famous Lockhart quality. Try harder next time."`,
                `"A bit crude, but I need a blade today. Next time, I hope the anvil's rhythm is more precise."`
            ][Math.floor(Math.random() * 3)];
        }
        return [
            `"Fantastic craftsmanship! This ${itemName} is exactly what I needed. Thank you, Lockhart!"`,
            `"Superb work. I feel much safer with this by my side. I'll be back!"`,
            `"A fair price for quality steel. May your bellows never tire, smith."`,
            `"You truly have the Lockhart touch. This will serve me well in the ruins."`
        ][Math.floor(Math.random() * 4)];
    }, [activeCustomer, lastSoldQuality, getItemName]);

    const getRefusalDialogue = useCallback(() => {
        if (refusalReaction === 'POLITE') {
            return [
                `"I see. Perhaps another time then. Safe forging, smith."`,
                `"Ah, a shame. I'll keep looking elsewhere for now."`,
                `"Understandable. A Lockhart's work shouldn't be rushed. Farewell."`,
                `"I'll come back when your anvil is hotter. Until next time."`
            ][(activeCustomer?.id.length || 0) % 4];
        } else {
            return [
                `"What? I walked all this way for nothing? Hmph. Don't expect me back soon."`,
                `"A cold welcome for a paying customer... I'll find a better forge."`,
                `"Unbelievable. My old blade has more edge than your business sense!"`,
                `"I thought the Lockharts were more reliable. Guess I was wrong."`
            ][(activeCustomer?.id.length || 0) % 4];
        }
    }, [refusalReaction, activeCustomer]);

    const tutorialContent = useMemo(() => {
        if (tutorialStep === 'PIP_PRAISE_DIALOG') {
            return {
                speaker: activeCustomer?.mercenary.name || "Pip the Green",
                text: "This... this is incredible. I can feel the balance in the grip. It's much better than the scraps I found in the woods. You really are a Lockhart, aren't you?",
                options: [{ label: "Continue", action: () => actions.setTutorialStep('DRAGON_TALK_DIALOG'), variant: 'primary' as const }]
            };
        }
        if (tutorialStep === 'DRAGON_TALK_DIALOG') {
            return {
                speaker: activeCustomer?.mercenary.name || "Pip the Green",
                text: "The village... it hasn't been the same since the Dragon's fire. I lost my brother that night. I see that same shadow in your eyes, smith. We all lost someone. Good luck with the forge.",
                options: [{ label: "Farewell", action: () => { handleFarewell(); actions.setTutorialStep('TUTORIAL_END_DIALOG'); }, variant: 'primary' as const }]
            };
        }
        if (tutorialStep === 'TUTORIAL_END_DIALOG') {
            return {
                speaker: "Lockhart",
                text: "Finally... the first sale. It's a small spark, but enough to light the way. I'll reclaim our legacy, one blade at a time.",
                options: [{ label: "Complete Tutorial", action: () => actions.completeTutorial(), variant: 'primary' as const }]
            };
        }
        return null;
    }, [tutorialStep, activeCustomer, actions, handleFarewell]);

    const dialogueState = useMemo(() => {
        if (tutorialContent) return tutorialContent;
        if (!activeCustomer) return null;

        if (saleCompleted) {
            return {
                speaker: activeCustomer.mercenary.name,
                text: getThanksDialogue(),
                options: [{ label: "Farewell", action: handleFarewell, variant: 'neutral' as const }]
            };
        }

        if (refusalReaction) {
            return {
                speaker: activeCustomer.mercenary.name,
                text: getRefusalDialogue(),
                options: [{ label: "Farewell", action: handleFarewell, variant: 'neutral' as const }]
            };
        }

        const { request, mercenary } = activeCustomer;
        const inventoryMatch = matchingItems.length > 0;

        // 아이템 정보 보완 (툴팁용)
        const isEquip = request.type === 'EQUIPMENT';
        const recipe = isEquip ? EQUIPMENT_ITEMS.find(e => e.id === request.requestedId) : null;
        const material = !isEquip ? Object.values(materials).find(m => m.id === request.requestedId) : null;

        return {
            speaker: mercenary.name,
            text: request.dialogue,
            highlightTerm: getItemName(request.requestedId),
            itemDetail: {
                id: request.requestedId, // ID만 전달하여 DialogueBox에서 'materials' 폴더 사용 유도
                icon: isEquip ? (recipe?.icon || '⚔️') : (material?.icon || '📦'),
                price: request.price,
                requirements: recipe?.requirements, // 제작 재료 추가
                isUnlocked: true
            },
            options: [
                { 
                    label: `Sell (${request.price} G)`, 
                    action: handleSellClick, 
                    variant: 'primary' as const, 
                    disabled: !inventoryMatch 
                },
                { 
                    label: "Refuse", 
                    action: handleRefuse, 
                    variant: 'danger' as const 
                }
            ]
        };
    }, [activeCustomer, saleCompleted, refusalReaction, matchingItems, tutorialContent, getThanksDialogue, getRefusalDialogue, handleFarewell, handleSellClick, handleRefuse, getItemName]);

    return {
        state,
        actions,
        isShopOpen,
        activeCustomer,
        shopQueue,
        floatingHearts,
        saleCompleted,
        refusalReaction,
        dialogueState,
        matchingItems,
        showInstanceSelector,
        selectedInstance,
        isTutorialActive: !!tutorialStep,
        canAffordOpen: state.stats.energy >= GAME_CONFIG.ENERGY_COST.OPEN_SHOP,
        handlers: {
            handleToggleShop,
            handleFarewell,
            handleSellClick,
            handleRefuse,
            setShowInstanceSelector,
            setSelectedInstance,
            executeSell
        }
    };
};

import React, { useState, useEffect, useRef, useCallback, useMemo } from 'react';
import { Shield, Sword, Activity, Skull, Zap, LogOut, FastForward, Pause, Play, ChevronDown, ChevronUp, Sparkles, Target, Package, X, Check, RotateCcw } from 'lucide-react';
import { Mercenary } from '../../../models/Mercenary';
import { Monster } from '../../../models/Monster';
import { ManualDungeonSession } from '../../../types/game-state';
import { calculateCombatResult } from '../../../utils/combatLogic';
import { calculateDerivedStats, applyEquipmentBonuses, mergePrimaryStats } from '../../../models/Stats';
import { useGame } from '../../../context/GameContext';
import { SKILLS } from '../../../data/skills';
import { MercenaryPortrait } from '../../common/ui/MercenaryPortrait';
import { getAssetUrl } from '../../../utils';
import { ItemSelectorList } from '../../ItemSelectorList';
import { InventoryItem, EquipmentSlotType } from '../../../types/inventory';
import { MercenaryDetailModal } from '../../modals/MercenaryDetailModal';

const ACTION_THRESHOLD = 1000;

interface CombatLogEntry {
    msg: string;
    team: 'PLAYER' | 'ENEMY' | 'SYSTEM';
    isCrit?: boolean;
    isSkill?: boolean;
}

interface DamagePopup {
    id: number;
    value: number;
    targetId: string;
    isCrit: boolean;
    isSkill: boolean;
}

interface DungeonCombatViewProps {
    session: ManualDungeonSession;
    party: Mercenary[];
    enemies: Monster[];
    fleeChance: number;
    onFinish: (win: boolean, finalParty: any[]) => void;
    onFlee: (finalParty: any[]) => void;
}

const DungeonCombatView: React.FC<DungeonCombatViewProps> = ({ party, enemies, fleeChance, onFinish, onFlee }) => {
    const { state, actions } = useGame();
    const [orientation, setOrientation] = useState<'PORTRAIT' | 'LANDSCAPE'>(
        window.innerWidth > window.innerHeight ? 'LANDSCAPE' : 'PORTRAIT'
    );

    const [partyState, setPartyState] = useState(party.map(m => {
        const primary = mergePrimaryStats(m.stats, m.allocatedStats);
        const derived = applyEquipmentBonuses(calculateDerivedStats(primary, m.level), (Object.values(m.equipment) as any[]).map(e=>e?.stats).filter(Boolean) as any);
        return { ...m, derived, currentHp: m.currentHp, currentMp: m.currentMp, gauge: 0, lastDamaged: false };
    }));

    const [enemySquadState, setEnemySquadState] = useState(enemies.map((e, idx) => ({
        ...e,
        instanceId: `enemy_${idx}`,
        gauge: 0,
        lastDamaged: false,
        hasUsedRevival: false
    })));

    const [logs, setLogs] = useState<CombatLogEntry[]>([]);
    const [damagePopups, setDamagePopups] = useState<DamagePopup[]>([]);
    const [isAuto, setIsAuto] = useState(true);
    const [isPaused, setIsPaused] = useState(false);
    const [battleSpeed, setBattleSpeed] = useState<1 | 2 | 4>(1);
    const [activeActorId, setActiveActorId] = useState<string | null>(null); 
    const [attackingUnitId, setAttackingUnitId] = useState<string | null>(null);
    const [showLogs, setShowLogs] = useState(false);

    const [pendingAction, setPendingAction] = useState<{ type: 'ATTACK' | 'SKILL', skillId?: string } | null>(null);
    const [inspectedMercId, setInspectedMercId] = useState<string | null>(null);

    const battleInterval = useRef<ReturnType<typeof setInterval> | null>(null);
    const speedRef = useRef(1);

    useEffect(() => {
        speedRef.current = battleSpeed;
    }, [battleSpeed]);

    useEffect(() => {
        const handleResize = () => {
            setOrientation(window.innerWidth > window.innerHeight ? 'LANDSCAPE' : 'PORTRAIT');
        };
        window.addEventListener('resize', handleResize);
        return () => window.removeEventListener('resize', handleResize);
    }, []);

    const addLog = (msg: string, team: 'PLAYER' | 'ENEMY' | 'SYSTEM', isCrit = false, isSkill = false) => {
        setLogs(prev => [{ msg, team, isCrit, isSkill }, ...prev].slice(0, 50));
    };

    const triggerDamagePopup = (targetId: string, value: number, isCrit: boolean, isSkill: boolean) => {
        const id = Date.now() + Math.random();
        setDamagePopups(prev => [...prev, { id, value, targetId, isCrit, isSkill }]);
        setTimeout(() => {
            setDamagePopups(prev => prev.filter(p => p.id !== id));
        }, 800 / speedRef.current);
    };

    const executeAttack = useCallback((attacker: any, target: any, isPlayerAttacker: boolean, skillId?: string) => {
        setAttackingUnitId(isPlayerAttacker ? attacker.id : target.instanceId);

        setTimeout(() => {
            const skill = skillId ? SKILLS[skillId] : null;
            const multiplier = skill ? skill.multiplier : 1.0;
            const mpCost = skill ? skill.mpCost : 0;

            const res = calculateCombatResult(
                isPlayerAttacker ? attacker.derived : attacker.stats,
                isPlayerAttacker ? target.stats : target.derived,
                isPlayerAttacker ? attacker.job : 'Fighter' as any,
                isPlayerAttacker ? (attacker.derived.magicalAttack > attacker.derived.physicalAttack ? 'MAGICAL' : 'PHYSICAL') : 'PHYSICAL',
                multiplier
            );

            if (isPlayerAttacker) {
                setEnemySquadState(prev => prev.map(e => {
                    if (e.instanceId === target.instanceId) {
                        const next = { ...e, lastDamaged: res.isHit };
                        if (res.isHit) {
                            let nextHp = Math.max(0, next.currentHp - res.damage);
                            if (nextHp <= 0 && next.id === 'phoenix' && !next.hasUsedRevival) {
                                nextHp = next.stats.maxHp;
                                next.hasUsedRevival = true;
                                addLog("Phoenix rebirth triggered!", 'ENEMY', true, true);
                                triggerDamagePopup(target.instanceId, 0, true, true);
                            } else {
                                next.currentHp = nextHp;
                            }
                            triggerDamagePopup(target.instanceId, res.damage, res.isCrit, !!skill);
                        }
                        setTimeout(() => setEnemySquadState(curr => curr.map(currE => currE.instanceId === target.instanceId ? { ...currE, lastDamaged: false } : currE)), 200 / speedRef.current);
                        return next;
                    }
                    return e;
                }));

                if (skill) {
                    setPartyState(prev => prev.map(p => p.id === attacker.id ? { ...p, currentMp: Math.max(0, p.currentMp - mpCost) } : p));
                    addLog(`${attacker.name.split(' ')[0]} used ${skill.name}!`, 'PLAYER', res.isCrit, true);
                } else {
                    addLog(`${attacker.name.split(' ')[0]} hits ${target.name} for ${res.damage}`, 'PLAYER', res.isCrit);
                }
            } else {
                setPartyState(prev => prev.map(p => {
                    if (p.id === target.id) {
                        const next = { ...p, lastDamaged: res.isHit };
                        if (res.isHit) {
                            next.currentHp = Math.max(0, next.currentHp - res.damage);
                            triggerDamagePopup(p.id, res.damage, res.isCrit, false);
                        }
                        setTimeout(() => setPartyState(curr => curr.map(c => c.id === p.id ? { ...c, lastDamaged: false } : c)), 200 / speedRef.current);
                        return next;
                    }
                    return p;
                }));
                addLog(`${attacker.name} strikes ${target.name.split(' ')[0]} for ${res.damage}`, 'ENEMY');
            }

            setTimeout(() => setAttackingUnitId(null), 150 / speedRef.current);
        }, 200 / speedRef.current);
    }, [addLog]);

    const processLoop = useCallback(() => {
        if (isPaused || activeActorId || attackingUnitId || inspectedMercId) return;

        setPartyState(prevParty => {
            const nextParty = [...prevParty];
            setEnemySquadState(prevEnemySquad => {
                const nextEnemySquad = [...prevEnemySquad];

                nextParty.forEach(p => { if (p.currentHp > 0) p.gauge += p.derived.speed * 0.5 * speedRef.current; });
                nextEnemySquad.forEach(e => { if (e.currentHp > 0) e.gauge += e.stats.speed * 0.5 * speedRef.current; });

                const readyMerc = nextParty.find(p => p.currentHp > 0 && p.gauge >= ACTION_THRESHOLD);
                if (readyMerc) {
                    const livingEnemies = nextEnemySquad.filter(e => e.currentHp > 0);
                    if (livingEnemies.length > 0) {
                        if (isAuto) {
                            readyMerc.gauge -= ACTION_THRESHOLD;
                            const targetEnemy = livingEnemies[0]; 
                            let chosenSkillId: string | undefined = undefined;
                            if (readyMerc.skillIds && readyMerc.skillIds.length > 0) {
                                const availableSkills = readyMerc.skillIds.map(id => SKILLS[id]).filter(s => readyMerc.currentMp >= s.mpCost);
                                if (availableSkills.length > 0) {
                                    chosenSkillId = availableSkills.sort((a, b) => b.multiplier - a.multiplier)[0].id;
                                }
                            }
                            executeAttack(readyMerc, targetEnemy, true, chosenSkillId);
                        } else {
                            setActiveActorId(readyMerc.id);
                        }
                    }
                }

                const readyEnemy = nextEnemySquad.find(e => e.currentHp > 0 && e.gauge >= ACTION_THRESHOLD);
                if (readyEnemy && !activeActorId && !attackingUnitId) {
                    const livingPlayers = nextParty.filter(p => p.currentHp > 0);
                    if (livingPlayers.length > 0) {
                        readyEnemy.gauge -= ACTION_THRESHOLD;
                        const targetPlayer = livingPlayers[Math.floor(Math.random() * livingPlayers.length)];
                        executeAttack(readyEnemy, targetPlayer, false);
                    }
                }

                return nextEnemySquad;
            });
            return nextParty;
        });
    }, [isPaused, isAuto, activeActorId, attackingUnitId, executeAttack, inspectedMercId]);

    useEffect(() => {
        battleInterval.current = setInterval(processLoop, 100);
        return () => { if (battleInterval.current) clearInterval(battleInterval.current); };
    }, [processLoop]);

    const handleTurnConsumed = useCallback((targetMercId: string) => {
        setTimeout(() => {
            const updatedMercFromContext = state.knownMercenaries.find(m => m.id === targetMercId);
            if (updatedMercFromContext) {
                setPartyState(prev => prev.map(p => {
                    if (p.id === targetMercId) {
                        const primary = mergePrimaryStats(updatedMercFromContext.stats, updatedMercFromContext.allocatedStats);
                        const derived = applyEquipmentBonuses(
                            calculateDerivedStats(primary, updatedMercFromContext.level), 
                            (Object.values(updatedMercFromContext.equipment) as any[]).map(e=>e?.stats).filter(Boolean) as any
                        );
                        return { 
                            ...p, 
                            ...updatedMercFromContext, 
                            derived,
                            currentHp: updatedMercFromContext.currentHp,
                            currentMp: updatedMercFromContext.currentMp,
                            gauge: Math.max(0, p.gauge - ACTION_THRESHOLD)
                        };
                    }
                    return p;
                }));
                setInspectedMercId(null);
                setActiveActorId(null);
            }
        }, 50);
    }, [state.knownMercenaries]);

    const handleManualCommand = (type: 'ATTACK' | 'FLEE' | 'SKILL' | 'INVENTORY', skillId?: string) => {
        if (!activeActorId) return;
        const actor = partyState.find(p => p.id === activeActorId);
        if (!actor) return;

        if (type === 'ATTACK') {
            setPendingAction({ type: 'ATTACK' });
        } else if (type === 'SKILL' && skillId) {
            setPendingAction({ type: 'SKILL', skillId });
        } else if (type === 'INVENTORY') {
            setInspectedMercId(activeActorId);
        } else if (type === 'FLEE') {
            const roll = Math.random() * 100;
            if (roll < fleeChance) {
                onFlee(partyState);
            } else {
                addLog(`${actor.name.split(' ')[0]} failed to find escape route!`, 'SYSTEM');
                setPartyState(prev => prev.map(p => p.id === activeActorId ? { ...p, gauge: p.gauge - ACTION_THRESHOLD } : p));
                setActiveActorId(null);
            }
        }
    };

    const handleEnemyClick = (target: any) => {
        if (!activeActorId || !pendingAction) return;
        if (target.currentHp <= 0) return;

        const actor = partyState.find(p => p.id === activeActorId);
        if (!actor) return;

        setPartyState(prev => prev.map(p => p.id === activeActorId ? { ...p, gauge: p.gauge - ACTION_THRESHOLD } : p));
        executeAttack(actor, target, true, pendingAction.skillId);
        setPendingAction(null);
        setActiveActorId(null);
    };

    useEffect(() => {
        if (enemySquadState.every(e => e.currentHp <= 0)) {
            setIsPaused(true);
            setTimeout(() => onFinish(true, partyState), 1200 / speedRef.current);
        } else if (partyState.every(p => p.currentHp <= 0)) {
            setIsPaused(true);
            setTimeout(() => onFinish(false, partyState), 1200 / speedRef.current);
        }
    }, [enemySquadState, partyState, onFinish]);

    const getUnitStyle = (id: string, side: 'PLAYER' | 'ENEMY'): React.CSSProperties => {
        if (attackingUnitId !== id) return {};

        let transform = '';
        if (orientation === 'PORTRAIT') {
            transform = side === 'PLAYER' ? 'translateY(-120px) scale(1.1)' : 'translateY(120px) scale(1.1)';
        } else {
            transform = side === 'PLAYER' ? 'translateX(120px) scale(1.1)' : 'translateX(-120px) scale(1.1)';
        }

        return { transform, zIndex: 100 };
    };

    return (
        <div className="fixed inset-0 z-[150] flex flex-col bg-stone-950 animate-in fade-in duration-500 overflow-hidden select-none font-sans pb-safe">
            <style>{`
                @keyframes damage-float {
                    0% { transform: translateY(0) scale(0.8); opacity: 0; }
                    20% { opacity: 1; scale: 1.2; }
                    100% { transform: translateY(-60px) scale(1.0); opacity: 0; }
                }
                .animate-damage { animation: damage-float 1s cubic-bezier(0.2, 0.8, 0.2, 1) forwards; }

                @keyframes unit-shake {
                    0%, 100% { transform: translate(0,0); }
                    25% { transform: translate(-4px, 2px); }
                    50% { transform: translate(4px, -2px); }
                    75% { transform: translate(-2px, -4px); }
                }
                .animate-hit { animation: unit-shake 0.2s ease-in-out 3; }

                @keyframes target-pulse {
                    0% { transform: scale(1); box-shadow: 0 0 0 0 rgba(239, 68, 68, 0.7); }
                    70% { transform: scale(1.05); box-shadow: 0 0 0 15px rgba(239, 68, 68, 0); }
                    100% { transform: scale(1); box-shadow: 0 0 0 0 rgba(239, 68, 68, 0); }
                }
                .animate-target { animation: target-pulse 1.5s infinite; }
            `}</style>

            {/* Top Toolbar */}
            <div className="p-3 bg-red-950/20 border-b border-red-900/30 flex justify-between items-center shrink-0 z-[200] gap-2">
                <div className="flex items-center gap-2">
                    <Skull className="w-4 h-4 text-red-50" />
                    <h2 className="text-white font-black uppercase text-[10px] md:text-sm tracking-widest font-mono hidden xs:block">Combat Zone</h2>
                </div>

                <div className="flex items-center gap-1 md:gap-3 bg-black/40 px-3 py-1 rounded-full border border-white/5">
                    <button 
                        onClick={() => setIsPaused(!isPaused)}
                        className={`p-1.5 rounded-full transition-all active:scale-90 ${isPaused ? 'bg-amber-600 text-white' : 'bg-stone-800 text-stone-400 hover:text-stone-200'}`}
                    >
                        {isPaused ? <Play className="w-3.5 h-3.5" /> : <Pause className="w-3.5 h-3.5" />}
                    </button>
                    <div className="w-px h-4 bg-stone-700" />
                    <div className="flex items-center gap-1">
                        {[1, 2, 4].map(s => (
                            <button 
                                key={s} 
                                onClick={() => setBattleSpeed(s as any)}
                                className={`px-2.5 py-0.5 rounded font-mono text-[9px] font-black transition-all ${battleSpeed === s ? 'bg-indigo-600 text-white shadow-glow-sm' : 'text-stone-600 hover:text-stone-400'}`}
                            >
                                {s}x
                            </button>
                        ))}
                    </div>
                </div>

                <div className="flex items-center gap-2">
                    <button 
                        onClick={() => { setIsAuto(!isAuto); setPendingAction(null); }}
                        className={`flex items-center gap-2 px-3 md:px-4 py-1.5 rounded-lg border font-black text-[9px] md:text-[10px] uppercase tracking-widest transition-all ${isAuto ? 'bg-amber-600 border-amber-400 text-white shadow-glow-sm' : 'bg-stone-800 border-stone-600 text-stone-400'}`}
                    >
                        {isAuto ? <FastForward className="w-3 h-3" /> : <Pause className="w-3 h-3" />}
                        <span className="font-black">{isAuto ? 'AUTO' : 'MANUAL'}</span>
                    </button>
                </div>
            </div>

            {/* MAIN COMBAT AREA (Center) */}
            <div className={`flex-1 flex relative overflow-hidden transition-all duration-700 ${orientation === 'PORTRAIT' ? 'flex-col' : 'flex-row'}`}>
                <div className="absolute inset-0 opacity-[0.02] pointer-events-none" style={{ backgroundImage: 'radial-gradient(circle, #fff 1px, transparent 1px)', backgroundSize: '40px 40px' }} />

                {/* SQUAD AREA: ENEMIES */}
                <div className={`flex flex-1 items-center justify-center p-2 sm:p-4 gap-3 md:gap-6 ${orientation === 'PORTRAIT' ? 'order-1' : 'order-2'}`}>
                    {enemySquadState.map((e) => {
                        const canTarget = !!pendingAction && e.currentHp > 0;
                        return (
                            <div 
                                key={e.instanceId} 
                                style={getUnitStyle(e.instanceId, 'ENEMY')}
                                onClick={() => canTarget && handleEnemyClick(e)}
                                className={`relative flex flex-col items-center transition-all duration-300 ease-out cursor-pointer ${e.currentHp <= 0 ? 'grayscale opacity-20 scale-90 cursor-default' : e.lastDamaged ? 'animate-hit' : ''}`}
                            >
                                <div className={`w-16 h-16 md:w-32 md:h-32 bg-stone-900/60 rounded-2xl border-2 flex items-center justify-center relative shadow-2xl transition-all ${e.lastDamaged ? 'border-red-500 bg-red-950/20' : 'border-stone-800'} ${attackingUnitId === e.instanceId ? 'ring-4 ring-red-500/40' : ''} ${canTarget ? 'animate-target border-red-500/50 scale-105' : ''}`}>
                                    <div className="w-[85%] h-[85%] flex items-center justify-center relative overflow-hidden">
                                        <img 
                                            src={getAssetUrl(e.sprite || 'giant_rat.png', 'monsters')} 
                                            className="w-full h-full object-contain drop-shadow-[0_4px_10px_rgba(0,0,0,0.5)]" 
                                            alt={e.name}
                                        />
                                    </div>
                                    {canTarget && (
                                        <div className="absolute inset-0 flex items-center justify-center bg-red-900/20 rounded-2xl">
                                            <Target className="w-8 h-8 text-red-500 drop-shadow-lg" />
                                        </div>
                                    )}
                                    <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                        {damagePopups.filter(p => p.targetId === e.instanceId).map(p => (
                                            <div key={p.id} className={`absolute font-black text-2xl md:text-4xl animate-damage drop-shadow-[0_4px_6px_rgba(0,0,0,1)] ${p.isSkill ? 'text-blue-400' : p.isCrit ? 'text-amber-400' : 'text-red-500'}`}>
                                                -{p.value}
                                            </div>
                                        ))}
                                    </div>
                                </div>
                                {e.currentHp > 0 && (
                                    <div className="mt-2 w-16 md:w-36 space-y-1">
                                        <div className="text-[7px] font-black text-stone-500 text-center uppercase tracking-tighter truncate leading-none">
                                            Lv.{e.level} {e.name}
                                        </div>
                                        <div className="relative h-2 bg-black rounded-full overflow-hidden border border-white/5">
                                            <div className="h-full bg-red-600 rounded-full transition-all duration-500" style={{ width: `${(e.currentHp/e.stats.maxHp)*100}%` }} />
                                            <div className="absolute inset-0 flex items-center justify-center">
                                                <span className="text-[6px] md:text-[8px] font-mono font-black text-white drop-shadow-sm">{Math.floor(e.currentHp)}/{e.stats.maxHp}</span>
                                            </div>
                                        </div>
                                        <div className="h-1 bg-black rounded-full overflow-hidden border border-white/5">
                                            <div className="h-full bg-amber-500 transition-all duration-100" style={{ width: `${(e.gauge/ACTION_THRESHOLD)*100}%` }} />
                                        </div>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>

                {/* SQUAD AREA: PLAYERS */}
                <div className={`flex flex-1 items-center justify-center p-2 sm:p-4 gap-3 md:gap-6 ${orientation === 'PORTRAIT' ? 'order-3 pt-0 pb-8' : 'order-1'}`}>
                    {partyState.map((p) => {
                        const isActive = activeActorId === p.id;
                        const hpPer = (p.currentHp / p.derived.maxHp) * 100;
                        const mpPer = (p.currentMp / (p.derived.maxMp || 1)) * 100;
                        const isReady = p.gauge >= ACTION_THRESHOLD;

                        return (
                            <div 
                                key={p.id} 
                                style={getUnitStyle(p.id, 'PLAYER')}
                                className={`relative flex flex-col items-center transition-all duration-300 ease-out ${p.currentHp <= 0 ? 'grayscale opacity-20 scale-90' : isActive ? '-translate-y-2' : ''} ${p.lastDamaged ? 'animate-hit' : ''}`}
                            >
                                <div className={`w-16 h-16 md:w-32 md:h-32 bg-stone-900/60 rounded-2xl border-2 flex items-center justify-center relative shadow-2xl transition-all ${isActive ? 'border-amber-400 bg-amber-900/10 ring-4 ring-amber-500/20' : 'border-stone-800'} ${attackingUnitId === p.id ? 'ring-4 ring-amber-400/50' : ''}`}>
                                    <MercenaryPortrait mercenary={p} className="w-[85%] h-[85%] rounded-xl" />
                                    {isReady && !isAuto && p.currentHp > 0 && (
                                        <div className="absolute -top-1.5 -right-1.5 w-6 h-6 bg-amber-500 rounded-full border-2 border-stone-900 flex items-center justify-center animate-bounce z-20 shadow-lg">
                                            <Zap className="w-3.5 h-3.5 text-stone-900 fill-stone-900" />
                                        </div>
                                    )}
                                    <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                        {damagePopups.filter(dp => dp.targetId === p.id).map(dp => (
                                            <div key={dp.id} className="absolute font-black text-2xl md:text-4xl animate-damage text-red-50 drop-shadow-[0_4px_6px_rgba(0,0,0,1)]">
                                                -{dp.value}
                                            </div>
                                        ))}
                                    </div>
                                </div>
                                {p.currentHp > 0 && (
                                    <div className="mt-2 w-16 md:w-40 space-y-1">
                                        <div className="flex flex-col items-center leading-none">
                                            <span className="text-[7px] font-black text-stone-400 uppercase tracking-tighter truncate">{p.name.split(' ')[0]}</span>
                                            <span className="text-[6px] font-bold text-stone-500 uppercase tracking-tighter">{p.job} • Lv.{p.level}</span>
                                        </div>
                                        <div className="relative h-2 bg-black rounded-full overflow-hidden border border-white/5">
                                            <div className={`h-full transition-all duration-500 ${hpPer < 30 ? 'bg-red-500 animate-pulse' : 'bg-red-600'}`} style={{ width: `${hpPer}%` }} />
                                            <div className="absolute inset-0 flex items-center justify-center">
                                                <span className="text-[6px] md:text-[8px] font-mono font-black text-white drop-shadow-sm">{Math.floor(p.currentHp)}/{p.derived.maxHp}</span>
                                            </div>
                                        </div>
                                        <div className="relative h-1.5 bg-black rounded-full overflow-hidden border border-white/5">
                                            <div className="h-full bg-blue-600 transition-all duration-500" style={{ width: `${mpPer}%` }} />
                                            <div className="absolute inset-0 flex items-center justify-center">
                                                <span className="text-[5px] md:text-[7px] font-mono font-black text-white drop-shadow-sm">{Math.floor(p.currentMp)}/{p.derived.maxMp}</span>
                                            </div>
                                        </div>
                                        <div className="h-1 bg-black rounded-full overflow-hidden border border-white/5">
                                            <div className="h-full bg-amber-500 transition-all duration-100" style={{ width: `${(p.gauge/ACTION_THRESHOLD)*100}%` }} />
                                        </div>
                                    </div>
                                )}

                                {isActive && !pendingAction && (
                                    <div className={`absolute ${orientation === 'PORTRAIT' ? 'bottom-full mb-4' : 'top-full mt-4'} left-1/2 -translate-x-1/2 z-[300] animate-in ${orientation === 'PORTRAIT' ? 'slide-in-from-bottom-4' : 'slide-in-from-top-4'} duration-300`}>
                                        <div className="flex flex-col gap-2 bg-stone-900/95 backdrop-blur-xl border-2 border-amber-500 p-2 rounded-2xl shadow-[0_0_50px_rgba(0,0,0,0.9)] w-40 md:w-52">
                                            <button 
                                                onClick={() => handleManualCommand('ATTACK')}
                                                className="w-full py-2.5 bg-stone-800 hover:bg-stone-700 text-white rounded-xl text-[10px] md:text-xs font-black uppercase flex items-center justify-center gap-2 transition-all active:scale-95"
                                            >
                                                <Sword className="w-3.5 h-3.5 text-amber-500" /> Attack
                                            </button>
                                            <div className="grid grid-cols-2 gap-2">
                                                <button 
                                                    onClick={() => handleManualCommand('INVENTORY')}
                                                    className="py-2.5 bg-indigo-900/40 hover:bg-indigo-900/60 text-indigo-100 rounded-xl text-[10px] md:text-xs font-black uppercase flex flex-col items-center justify-center gap-1 transition-all border border-indigo-500/30"
                                                >
                                                    <Package className="w-3.5 h-3.5" />
                                                    <span>Bag</span>
                                                </button>
                                                <button 
                                                    onClick={() => handleManualCommand('FLEE')}
                                                    className="py-2.5 bg-red-950/40 hover:bg-red-900/60 text-red-500 rounded-xl text-[10px] md:text-xs font-black uppercase flex flex-col items-center justify-center gap-1 transition-all border border-red-500/30"
                                                >
                                                    <LogOut className="w-3.5 h-3.5" />
                                                    <span>Retreat</span>
                                                </button>
                                            </div>
                                            {p.skillIds?.map(id => {
                                                const skill = SKILLS[id];
                                                const canUse = p.currentMp >= (skill?.mpCost || 0);
                                                if (!skill) return null;
                                                return (
                                                    <button 
                                                        key={id}
                                                        disabled={!canUse}
                                                        onClick={() => handleManualCommand('SKILL', id)}
                                                        className={`w-full py-2 rounded-xl text-[9px] md:text-[10px] font-black uppercase flex flex-col items-center justify-center border-b-2 transition-all ${canUse ? 'bg-amber-600 border-amber-800 text-white hover:bg-amber-500 active:scale-95' : 'bg-stone-950 border-stone-800 text-stone-700'}`}
                                                    >
                                                        <div className="flex items-center gap-1">
                                                            <Sparkles className="w-3 h-3" />
                                                            <span>{skill.name}</span>
                                                        </div>
                                                        <span className="text-[7px] opacity-70">{skill.mpCost} MP</span>
                                                    </button>
                                                );
                                            })}
                                        </div>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>

                {/* Targeting Instruction Overlay */}
                {pendingAction && (
                    <div className="absolute inset-0 z-[250] flex flex-col items-center justify-center bg-black/40 backdrop-blur-[2px] pointer-events-none animate-in fade-in duration-300">
                        <div className="bg-red-900/90 border-2 border-red-500 px-8 py-4 rounded-full shadow-[0_0_50px_rgba(239,68,68,0.4)] flex items-center gap-4">
                            <Target className="w-8 h-8 text-white animate-pulse" />
                            <div className="flex flex-col">
                                <span className="text-white font-black uppercase tracking-[0.2em] text-sm md:text-lg">Select Targeting Objective</span>
                                <span className="text-red-200 text-[10px] uppercase font-bold opacity-70">Click on an enemy unit to execute {pendingAction.type === 'SKILL' ? SKILLS[pendingAction.skillId!]?.name : 'Attack'}</span>
                            </div>
                            <button 
                                onClick={(e) => { e.stopPropagation(); setPendingAction(null); }}
                                className="pointer-events-auto ml-4 p-2 bg-black/40 hover:bg-black/60 rounded-full text-white transition-colors"
                            >
                                <X className="w-6 h-6" />
                            </button>
                        </div>
                    </div>
                )}
            </div>

            {/* TACTICAL FEED (Now at Bottom) */}
            <div className={`bg-stone-900 border-t border-stone-800 transition-all duration-500 flex flex-col shrink-0 z-[200] ${showLogs ? 'h-48 md:h-60' : 'h-10 md:h-12'}`}>
                <button 
                    onClick={() => setShowLogs(!showLogs)}
                    className="w-full min-h-[40px] md:min-h-[48px] flex items-center justify-between px-4 bg-stone-950/40 hover:bg-stone-950/60 transition-colors gap-4"
                >
                    <div className="flex items-center gap-2 min-w-0 flex-1">
                        <Target className={`w-4 h-4 shrink-0 ${isPaused ? 'text-stone-500' : 'text-red-500 animate-pulse'}`} />
                        <div className="flex-1 min-w-0 text-left">
                            {!showLogs && logs[0] ? (
                                <p className={`text-[10px] md:text-sm font-mono font-black uppercase truncate tracking-tight ${logs[0].isCrit ? 'text-amber-400' : logs[0].team === 'PLAYER' ? 'text-blue-300' : logs[0].team === 'ENEMY' ? 'text-red-300' : 'text-stone-300'}`}>
                                    {logs[0].msg}
                                </p>
                            ) : (
                                <span className="text-[9px] md:text-[11px] font-black text-stone-400 uppercase tracking-[0.2em] font-mono">Real-time Engagement Feed</span>
                            )}
                        </div>
                    </div>
                    {showLogs ? <ChevronDown className="w-4 h-4 text-stone-600 shrink-0" /> : <ChevronUp className="w-4 h-4 text-stone-600 shrink-0" />}
                </button>

                <div className={`flex-1 overflow-y-auto custom-scrollbar p-1.5 space-y-1 bg-stone-950/30 ${showLogs ? 'opacity-100' : 'opacity-0 pointer-events-none'}`}>
                    {logs.map((log, idx) => (
                        <div key={idx} className={`text-[10px] md:text-[11px] font-mono px-3 py-1.5 border-l-4 rounded-r-sm leading-relaxed break-words ${log.isSkill ? 'border-amber-400 bg-amber-900/10' : log.team === 'PLAYER' ? 'border-blue-500 text-blue-100 bg-blue-900/5' : log.team === 'ENEMY' ? 'border-red-500 text-red-100 bg-red-900/5' : 'border-stone-500 text-stone-400'}`}>
                            <span className="opacity-30 mr-2 text-[9px] font-bold inline-block align-top">{new Date().toLocaleTimeString([], { hour12: false, minute: '2-digit', second: '2-digit' })}</span>
                            <span className="inline-block align-top">{log.msg}</span>
                        </div>
                    ))}
                    {logs.length === 0 && <div className="h-full flex items-center justify-center text-stone-800 italic text-[10px] md:text-sm uppercase tracking-widest opacity-40 font-mono">Initializing tactical arrays...</div>}
                </div>
            </div>

            {/* Combat Inventory / Mercenary Detail Modal */}
            {inspectedMercId && (
                <div className="fixed inset-0 z-[1000] flex items-center justify-center p-4 bg-black/90 backdrop-blur-md animate-in fade-in duration-300">
                    <div className="bg-indigo-900/20 border-2 border-indigo-500/30 px-6 py-2 rounded-full mb-4 flex items-center gap-3 shadow-glow-sm">
                        <Zap className="w-4 h-4 text-indigo-400" />
                        <span className="text-xs font-black text-indigo-100 uppercase tracking-widest">Combat Action: 1 AP Cost for Inventory Usage</span>
                    </div>

                    <div className="w-full max-w-5xl h-[85vh] relative">
                        <button 
                            onClick={() => setInspectedMercId(null)}
                            className="absolute -top-12 right-0 p-2 bg-red-900/40 hover:bg-red-600 rounded-full text-red-100 transition-all z-[1100]"
                        >
                            <X className="w-6 h-6" />
                        </button>

                        <MercenaryDetailModal 
                            mercenary={partyState.find(p => p.id === inspectedMercId) || null}
                            onClose={() => setInspectedMercId(null)}
                            onEquip={(mercId, itemId) => {
                                actions.equipItem(mercId, itemId);
                                handleTurnConsumed(mercId);
                            }}
                            onConsume={(mercId, itemId) => {
                                actions.useItem(itemId, mercId);
                                handleTurnConsumed(mercId);
                            }}
                            onUnequip={(mercId, slot) => {
                                actions.unequipItem(mercId, slot);
                                handleTurnConsumed(mercId);
                            }}
                            isReadOnly={false}
                        />
                    </div>
                </div>
            )}
        </div>
    );
};

export default DungeonCombatView;

import React, { useState, useEffect, useRef } from 'react';
import { createPortal } from 'react-dom';
import { User, ChevronRight, Coins, Package, Lock } from 'lucide-react';
import { useGame } from '../context/GameContext';
import { materials } from '../data/materials';
import { getAssetUrl } from '../utils';

interface DialogueOption {
  label: string;
  action: () => void;
  variant?: 'primary' | 'danger' | 'neutral';
  disabled?: boolean;
}

interface ItemDetail {
  id: string;
  icon: string;
  price: number;
  requirements?: { id: string; count: number }[];
  isUnlocked?: boolean;
}

interface DialogueBoxProps {
  speaker: string;
  text: string;
  options?: DialogueOption[];
  highlightTerm?: string;
  itemDetail?: ItemDetail;
  className?: string;
  speakerAvatar?: string;
}

const DialogueBox: React.FC<DialogueBoxProps> = ({ 
  speaker, 
  text, 
  options = [], 
  highlightTerm,
  itemDetail,
  className = "relative w-full z-40",
  speakerAvatar
}) => {
  const { state } = useGame();
  const [displayedIndex, setDisplayedIndex] = useState(0);
  const [isTyping, setIsTyping] = useState(false);
  const [showItemTooltip, setShowItemTooltip] = useState(false);
  const [tooltipCoords, setTooltipCoords] = useState({ x: 0, y: 0 });
  const [imgError, setImgError] = useState(false);

  const isMounted = useRef(true);
  const timerRef = useRef<ReturnType<typeof setInterval> | null>(null);
  const textContainerRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    isMounted.current = true;
    return () => { 
      isMounted.current = false;
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, []);

  // Debug: Tooltip Data Logging
  useEffect(() => {
    if (showItemTooltip && itemDetail) {
      const targetUrl = getAssetUrl(`${itemDetail.id}.png`, 'equipments');
      console.group('%c[Tooltip Debug]', 'color: #fbbf24; font-weight: bold;');
      console.log('Speaker:', speaker);
      console.log('Item Detail:', itemDetail);
      console.log('Generated Asset URL:', targetUrl);
      console.groupEnd();
    }
  }, [showItemTooltip, itemDetail, speaker]);

  useEffect(() => {
    if (textContainerRef.current) {
      const container = textContainerRef.current;
      const scrollHandle = requestAnimationFrame(() => {
        container.scrollTop = container.scrollHeight;
      });
      return () => cancelAnimationFrame(scrollHandle);
    }
  }, [displayedIndex, text, isTyping]);

  useEffect(() => {
    if (timerRef.current) clearInterval(timerRef.current);

    setDisplayedIndex(0);
    setIsTyping(true);
    setShowItemTooltip(false);
    setImgError(false);
    let index = 0;
    const speed = 25; 

    timerRef.current = setInterval(() => {
      if (!isMounted.current) return;

      index++;
      if (index > text.length) {
        if (timerRef.current) clearInterval(timerRef.current);
        setIsTyping(false);
        setDisplayedIndex(text.length);
      } else {
        setDisplayedIndex(index);
      }
    }, speed);

    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [text]);

  const handleSkipTyping = () => {
    if (isTyping) {
      if (timerRef.current) clearInterval(timerRef.current);
      setDisplayedIndex(text.length);
      setIsTyping(false);
    }
  };

  const getInventoryCount = (id: string) => {
    return state.inventory.find(i => i.id === id)?.quantity || 0;
  };

  const updateTooltipPosition = (e: React.MouseEvent | React.TouchEvent) => {
    const rect = (e.currentTarget as HTMLElement).getBoundingClientRect();
    setTooltipCoords({
      x: rect.left + rect.width / 2,
      y: rect.top
    });
  };

  const renderFormattedText = () => {
    if (!highlightTerm) {
      return <span>{text.slice(0, displayedIndex)}</span>;
    }

    const parts = text.split(new RegExp(`(${highlightTerm})`, 'g'));
    let charCount = 0;

    return parts.map((part, i) => {
      const startChar = charCount;
      const endChar = charCount + part.length;
      charCount = endChar;

      const visibleCountInPart = Math.max(0, Math.min(part.length, displayedIndex - startChar));
      if (visibleCountInPart <= 0) return null;

      const visiblePart = part.slice(0, visibleCountInPart);

      if (part === highlightTerm) {
        return (
          <span 
            key={i} 
            className="text-amber-400 font-black underline decoration-amber-500/50 underline-offset-4 cursor-pointer relative inline-block pointer-events-auto"
            onClick={(e) => { 
                e.stopPropagation(); 
                updateTooltipPosition(e); 
                setShowItemTooltip(!showItemTooltip); 
            }}
          >
            {visiblePart}
          </span>
        );
      }

      return <React.Fragment key={i}>{visiblePart}</React.Fragment>;
    });
  };

  const tooltipElement = showItemTooltip && itemDetail && createPortal(
    <div 
      className="fixed z-[10000] pointer-events-none p-3 md:p-4 bg-stone-900/98 backdrop-blur-2xl border-2 border-stone-700 rounded-2xl shadow-[0_20px_50px_rgba(0,0,0,0.9)] w-[80vw] max-w-[240px] md:max-w-[320px] animate-in fade-in zoom-in-95 duration-200"
      style={{ 
        left: `${Math.max(130, Math.min(window.innerWidth - 130, tooltipCoords.x))}px`, 
        top: `${tooltipCoords.y - 10}px`,
        transform: 'translate(-50%, -100%)'
      }}
    >
      <div className="flex items-center gap-3 mb-2 md:mb-3 pb-2 md:pb-3 border-b border-white/10">
        <div className={`w-10 h-10 md:w-16 md:h-16 bg-stone-950 rounded-xl border-2 flex items-center justify-center shadow-inner shrink-0 overflow-hidden ${!itemDetail.isUnlocked ? 'border-amber-600/50' : 'border-stone-800'}`}>
          {!itemDetail.isUnlocked ? (
            <span className="text-2xl md:text-4xl font-serif text-amber-500 font-black animate-pulse">?</span>
          ) : (
            <>
              {!imgError ? (
                <img 
                  src={getAssetUrl(`${itemDetail.id}.png`, 'equipments')} 
                  onError={(e) => {
                    console.error('[Tooltip Debug] Image Failed to Load:', (e.target as HTMLImageElement).src);
                    setImgError(true);
                  }}
                  className="w-7 h-7 md:w-11 md:h-11 object-contain" 
                  alt="item" 
                />
              ) : (
                <span className="text-xl md:text-3xl">{itemDetail.icon}</span>
              )}
            </>
          )}
        </div>
        <div className="flex flex-col leading-none">
          <span className="text-[7px] md:text-[10px] text-stone-500 font-black uppercase tracking-widest mb-1">Price</span>
          <div className={`flex items-center gap-1 font-mono font-black text-xs md:text-xl ${!itemDetail.isUnlocked ? 'text-stone-600' : 'text-emerald-400'}`}>
            <Coins className="w-3 h-3 md:w-5 md:h-5" />
            {!itemDetail.isUnlocked ? '???,???' : itemDetail.price.toLocaleString()} G
          </div>
        </div>
      </div>

      <div className="space-y-2">
        <h5 className="text-[7px] md:text-[9px] font-black text-stone-500 uppercase tracking-widest flex items-center gap-1.5">
          <Package className="w-2 h-2 md:w-3 md:h-3" /> Required Materials
        </h5>

        <div className="grid gap-1">
          {itemDetail.requirements && itemDetail.requirements.length > 0 ? (
            itemDetail.requirements.map((req, idx) => {
              const isClue = idx === 0; 
              const shouldShow = itemDetail.isUnlocked || isClue;

              if (!shouldShow) {
                return (
                  <div key={req.id} className="flex justify-between items-center text-[8px] md:text-xs opacity-40">
                    <span className="truncate mr-2 font-bold tracking-tight text-stone-600">
                      ???
                    </span>
                    <div className="flex items-center gap-1 shrink-0">
                      <span className="font-mono font-black text-stone-700">
                        ? / ?
                      </span>
                      <div className="w-1 h-1 rounded-full bg-stone-800" />
                    </div>
                  </div>
                );
              }

              const hasCount = getInventoryCount(req.id);
              const isEnough = hasCount >= req.count;
              const mat = Object.values(materials).find(m => m.id === req.id);

              return (
                <div key={req.id} className="flex justify-between items-center text-[8px] md:text-xs">
                  <span className={`truncate mr-2 font-bold tracking-tight ${isEnough ? 'text-stone-300' : 'text-red-400'}`}>
                    {mat?.name || req.id}
                  </span>
                  <div className="flex items-center gap-1 shrink-0">
                    <span className={`font-mono font-black ${isEnough ? 'text-stone-500' : 'text-red-500'}`}>
                      {hasCount}/{req.count}
                    </span>
                    <div className={`w-1 h-1 rounded-full ${isEnough ? 'bg-emerald-500 shadow-[0_0_4px_rgba(16,185,129,0.5)]' : 'bg-red-500 animate-pulse'}`} />
                  </div>
                </div>
              );
            })
          ) : (
            <div className="text-[8px] md:text-xs text-stone-600 italic">No specific requirements found.</div>
          )}
        </div>

        {!itemDetail.isUnlocked && (
          <div className="mt-2 pt-2 border-t border-white/5 flex flex-col items-center text-center">
            <div className="flex items-center gap-1.5 text-amber-600/80">
